    def approve_dataset2_training_execution(
        self,
        training_plan_id: str | None = None,
        approved_by: str = "operator",
        approval_decision: str = "approved_for_dataset2_training_dry_run",
        confirmation_token: str | None = None,
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Record operator approval metadata before any Dataset2 training dry-run can be requested."""
        store = SQLiteStore(settings.database_path)
        store.init()
        plan = self._dataset2_training_run_plan_by_plan_id(store, training_plan_id)
        plan_decision = (plan or {}).get("decision") or {}
        training_plan = (plan or {}).get("training_plan") or {}
        resolved_package_id = (plan or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        expected_token = "APPROVE_DATASET2_TRAINING_EXECUTION"
        expected_decision = "approved_for_dataset2_training_dry_run"
        training_plan_hash = self._stable_hash(training_plan) if training_plan else None
        plan_ready = (
            plan
            and (not training_plan_id or training_plan.get("plan_id") == training_plan_id)
            and plan.get("status") == "dataset2_training_run_plan_ready"
            and plan_decision.get("dataset2_training_run_plan_ready") is True
            and plan_decision.get("can_request_dataset2_training_execution_approval_now") is True
        )
        checks = [
            self._manual_evidence_check(
                "training_run_plan_ready",
                "passed" if plan_ready else "blocked",
                {
                    "latest_or_selected_plan_event_id": (plan or {}).get("id"),
                    "requested_training_plan_id": training_plan_id,
                    "resolved_training_plan_id": training_plan.get("plan_id"),
                    "plan_status": (plan or {}).get("status"),
                    "can_request_dataset2_training_execution_approval_now": plan_decision.get(
                        "can_request_dataset2_training_execution_approval_now"
                    ),
                },
                "matching ready P64 training run plan",
                "P65 can only record execution approval metadata after a ready P64 plan",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P65 requires explicit operator confirmation before recording training execution approval metadata",
            ),
            self._manual_evidence_check(
                "approval_decision_allowed",
                "passed" if approval_decision == expected_decision else "blocked",
                approval_decision,
                expected_decision,
                "P65 approval can only target a later Dataset2 training dry-run, not immediate training",
            ),
            self._manual_evidence_check(
                "dataset2_learning_samples_still_available",
                "passed" if rows else "blocked",
                {
                    "current_learning_sample_count": len(rows),
                    "planned_learning_sample_count": ((plan or {}).get("evidence") or {}).get("learning_sample_count"),
                },
                ">0 and consistent with P64 plan",
                "Dataset2 learning samples must still exist before approval metadata is recorded",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_plan",
                (
                    "passed"
                    if rows
                    and ((plan or {}).get("evidence") or {}).get("learning_sample_count") == len(rows)
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "planned_learning_sample_count": ((plan or {}).get("evidence") or {}).get("learning_sample_count"),
                },
                "current count equals P64 planned count",
                "Approval metadata must pin to the same promoted Dataset2 learning sample set as the P64 plan",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 training execution approval metadata cannot be recorded while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_training_execution_approval.v1",
            "stage": "V5.6-P65",
            "status": (
                "dataset2_training_execution_approval_accepted"
                if accepted
                else "dataset2_training_execution_approval_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "approval": {
                "approved_by": approved_by or "operator",
                "approval_decision": approval_decision,
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "approved_for_dataset2_training_dry_run": accepted,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "training_plan_event_id": (plan or {}).get("id"),
                "training_plan_id": training_plan.get("plan_id"),
                "training_plan_hash": training_plan_hash,
                "learning_sample_count": len(rows),
                "planned_learning_sample_count": ((plan or {}).get("evidence") or {}).get("learning_sample_count"),
                "model_family": training_plan.get("model_family"),
                "validation_policy": training_plan.get("validation_policy"),
                "source_type": "dataset2_staging",
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_dataset2_training_dry_run"
                    if accepted
                    else "resolve_dataset2_training_execution_approval_blocks"
                ),
            },
            "decision": {
                "dataset2_training_execution_approval_recorded": True,
                "dataset2_training_execution_approved_for_dry_run": accepted,
                "can_prepare_dataset2_training_dry_run_now": accepted,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_dataset2_training_dry_run"
                    if accepted
                    else "resolve_dataset2_training_execution_approval_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_training_execution_approval_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

