    def dataset2_training_dry_run(
        self,
        training_plan_id: str | None = None,
        approval_event_id: int | None = None,
        run_by: str = "operator",
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Run a no-artifact Dataset2 training dry-run after P65 approval metadata."""
        store = SQLiteStore(settings.database_path)
        store.init()
        approval = self._dataset2_training_execution_approval_by_id(store, approval_event_id)
        approval_decision = (approval or {}).get("decision") or {}
        approval_evidence = (approval or {}).get("evidence") or {}
        resolved_training_plan_id = training_plan_id or approval_evidence.get("training_plan_id")
        plan = self._dataset2_training_run_plan_by_plan_id(store, resolved_training_plan_id)
        training_plan = (plan or {}).get("training_plan") or {}
        resolved_package_id = (plan or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        planned_feature_keys = list(training_plan.get("feature_keys") or [])
        label_counts: Counter[str] = Counter()
        split_counts: Counter[str] = Counter()
        train_label_counts: Counter[str] = Counter()
        out_of_sample_label_counts: Counter[str] = Counter()
        feature_missing_counts: Counter[str] = Counter()
        out_of_sample_splits = {"validation", "valid", "test", "out_of_sample"}
        train_rows = 0
        out_of_sample_rows = 0
        sample_ids: list[str] = []
        for row in rows:
            features = json.loads(row.get("features_json") or "{}")
            label = str(row.get("label") or "unknown")
            split = str(features.get("split_tag") or "unknown")
            sample_ids.append(str(row.get("source_id") or row.get("id") or ""))
            label_counts[label] += 1
            split_counts[split] += 1
            if split == "train":
                train_rows += 1
                train_label_counts[label] += 1
            if split in out_of_sample_splits:
                out_of_sample_rows += 1
                out_of_sample_label_counts[label] += 1
            for key in planned_feature_keys:
                if features.get(key) in (None, "", [], {}):
                    feature_missing_counts[key] += 1
        majority_label = None
        if train_label_counts:
            majority_label = train_label_counts.most_common(1)[0][0]
        out_of_sample_correct = out_of_sample_label_counts.get(majority_label or "", 0)
        out_of_sample_accuracy = (
            round(out_of_sample_correct / out_of_sample_rows, 6)
            if out_of_sample_rows
            else None
        )
        plan_ready = (
            plan
            and plan.get("status") == "dataset2_training_run_plan_ready"
            and ((plan.get("decision") or {}).get("dataset2_training_run_plan_ready") is True)
        )
        approval_ready = (
            approval
            and approval.get("status") == "dataset2_training_execution_approval_accepted"
            and approval_decision.get("dataset2_training_execution_approved_for_dry_run") is True
        )
        checks = [
            self._manual_evidence_check(
                "training_execution_approval_accepted",
                "passed" if approval_ready else "blocked",
                {
                    "approval_event_id": (approval or {}).get("id"),
                    "approval_status": (approval or {}).get("status"),
                    "approved_for_dry_run": approval_decision.get("dataset2_training_execution_approved_for_dry_run"),
                },
                "accepted P65 approval",
                "P66 can only run after accepted P65 approval metadata",
            ),
            self._manual_evidence_check(
                "training_run_plan_ready",
                "passed" if plan_ready else "blocked",
                {
                    "training_plan_event_id": (plan or {}).get("id"),
                    "training_plan_id": training_plan.get("plan_id"),
                    "plan_status": (plan or {}).get("status"),
                },
                "ready P64 plan",
                "P66 must pin to a ready P64 training run plan",
            ),
            self._manual_evidence_check(
                "approval_matches_plan",
                (
                    "passed"
                    if approval_ready
                    and plan_ready
                    and approval_evidence.get("training_plan_id") == training_plan.get("plan_id")
                    else "blocked"
                ),
                {
                    "approval_training_plan_id": approval_evidence.get("training_plan_id"),
                    "resolved_training_plan_id": training_plan.get("plan_id"),
                },
                "matching plan id",
                "P66 dry-run must use the same training plan approved in P65",
            ),
            self._manual_evidence_check(
                "train_and_out_of_sample_rows_available",
                "passed" if train_rows > 0 and out_of_sample_rows > 0 else "blocked",
                {"train_rows": train_rows, "out_of_sample_rows": out_of_sample_rows},
                "train > 0 and out_of_sample > 0",
                "Dataset2 dry-run needs both training and out-of-sample rows",
            ),
            self._manual_evidence_check(
                "feature_columns_available",
                "passed" if planned_feature_keys else "blocked",
                planned_feature_keys[:20],
                "non-empty planned feature keys",
                "Dataset2 dry-run needs the feature keys planned in P64",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_approval",
                (
                    "passed"
                    if rows and approval_evidence.get("learning_sample_count") == len(rows)
                    else "blocked"
                ),
                {
                    "approval_learning_sample_count": approval_evidence.get("learning_sample_count"),
                    "current_learning_sample_count": len(rows),
                },
                "current count equals P65 approved count",
                "Dataset2 dry-run must use the same sample set approved in P65",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 training dry-run cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        completed = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_training_dry_run.v1",
            "stage": "V5.6-P66",
            "status": "dataset2_training_dry_run_completed" if completed else "dataset2_training_dry_run_blocked",
            "generated_at": now,
            "package_id": resolved_package_id,
            "run": {
                "run_by": run_by or "operator",
                "note": note,
                "record_bodies_included": False,
                "model_artifact_written": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "approval_event_id": (approval or {}).get("id"),
                "training_plan_event_id": (plan or {}).get("id"),
                "training_plan_id": training_plan.get("plan_id"),
                "learning_sample_count": len(rows),
                "sample_set_hash": self._stable_hash(sample_ids),
                "model_family": training_plan.get("model_family"),
                "validation_policy": training_plan.get("validation_policy"),
                "source_type": "dataset2_staging",
            },
            "dry_run": {
                "baseline_strategy": "train_majority_label_classifier",
                "majority_label": majority_label,
                "train_row_count": train_rows,
                "out_of_sample_row_count": out_of_sample_rows,
                "label_counts": dict(label_counts),
                "split_counts": dict(split_counts),
                "train_label_counts": dict(train_label_counts),
                "out_of_sample_label_counts": dict(out_of_sample_label_counts),
                "planned_feature_count": len(planned_feature_keys),
                "feature_missing_counts": dict(feature_missing_counts),
                "out_of_sample_accuracy": out_of_sample_accuracy,
                "model_artifact_written": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "review_dataset2_training_dry_run_results"
                    if completed
                    else "resolve_dataset2_training_dry_run_blocks"
                ),
            },
            "decision": {
                "dataset2_training_dry_run_recorded": True,
                "dataset2_training_dry_run_completed": completed,
                "can_prepare_dataset2_training_result_review_now": completed,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "review_dataset2_training_dry_run_results"
                    if completed
                    else "resolve_dataset2_training_dry_run_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_training_dry_run_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

