    def dataset2_training_dry_run_review(
        self,
        dry_run_event_id: int | None = None,
        reviewed_by: str = "operator",
        review_decision: str = "accepted_for_controlled_training_execution_plan",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Review P66 dry-run evidence before any controlled training execution plan is prepared."""
        store = SQLiteStore(settings.database_path)
        store.init()
        dry_run = self._dataset2_training_dry_run_by_id(store, dry_run_event_id)
        dry_decision = (dry_run or {}).get("decision") or {}
        dry_evidence = (dry_run or {}).get("evidence") or {}
        dry_metrics = (dry_run or {}).get("dry_run") or {}
        allowed_decision = "accepted_for_controlled_training_execution_plan"
        dry_run_ready = (
            dry_run
            and dry_run.get("status") == "dataset2_training_dry_run_completed"
            and dry_decision.get("dataset2_training_dry_run_completed") is True
            and dry_decision.get("can_prepare_dataset2_training_result_review_now") is True
        )
        artifact_blocked = (
            dry_metrics.get("model_artifact_written") is False
            and dry_decision.get("model_artifact_written") is False
            and dry_decision.get("training_started_now") is False
        )
        train_rows = int(dry_metrics.get("train_row_count") or 0)
        out_rows = int(dry_metrics.get("out_of_sample_row_count") or 0)
        accuracy = dry_metrics.get("out_of_sample_accuracy")
        checks = [
            self._manual_evidence_check(
                "training_dry_run_completed",
                "passed" if dry_run_ready else "blocked",
                {
                    "dry_run_event_id": (dry_run or {}).get("id"),
                    "dry_run_status": (dry_run or {}).get("status"),
                    "can_prepare_dataset2_training_result_review_now": dry_decision.get(
                        "can_prepare_dataset2_training_result_review_now"
                    ),
                },
                "completed P66 dry-run",
                "P67 can only review completed P66 dry-run evidence",
            ),
            self._manual_evidence_check(
                "review_decision_allowed",
                "passed" if review_decision == allowed_decision else "blocked",
                review_decision,
                allowed_decision,
                "P67 review can only accept evidence for a later controlled training execution plan",
            ),
            self._manual_evidence_check(
                "train_and_out_of_sample_evidence_present",
                "passed" if train_rows > 0 and out_rows > 0 else "blocked",
                {"train_rows": train_rows, "out_of_sample_rows": out_rows},
                "train > 0 and out_of_sample > 0",
                "Dry-run review needs train and out-of-sample evidence",
            ),
            self._manual_evidence_check(
                "baseline_metric_recorded",
                "passed" if isinstance(accuracy, int | float) else "blocked",
                accuracy,
                "numeric out_of_sample_accuracy",
                "P67 needs a baseline out-of-sample metric before preparing controlled training execution",
            ),
            self._manual_evidence_check(
                "sample_set_hash_recorded",
                "passed" if bool(dry_evidence.get("sample_set_hash")) else "blocked",
                dry_evidence.get("sample_set_hash"),
                "non-empty sample_set_hash",
                "P67 must pin review evidence to a deterministic Dataset2 sample set hash",
            ),
            self._manual_evidence_check(
                "no_model_artifact_or_training_started",
                "passed" if artifact_blocked else "blocked",
                {
                    "dry_run_model_artifact_written": dry_metrics.get("model_artifact_written"),
                    "decision_model_artifact_written": dry_decision.get("model_artifact_written"),
                    "training_started_now": dry_decision.get("training_started_now"),
                },
                "all false",
                "P67 must confirm P66 did not write model artifacts or start training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 dry-run review cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_training_dry_run_review.v1",
            "stage": "V5.6-P67",
            "status": (
                "dataset2_training_dry_run_review_accepted"
                if accepted
                else "dataset2_training_dry_run_review_blocked"
            ),
            "generated_at": now,
            "package_id": (dry_run or {}).get("package_id"),
            "review": {
                "reviewed_by": reviewed_by or "operator",
                "review_decision": review_decision,
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "dry_run_event_id": (dry_run or {}).get("id"),
                "approval_event_id": dry_evidence.get("approval_event_id"),
                "training_plan_event_id": dry_evidence.get("training_plan_event_id"),
                "training_plan_id": dry_evidence.get("training_plan_id"),
                "sample_set_hash": dry_evidence.get("sample_set_hash"),
                "learning_sample_count": dry_evidence.get("learning_sample_count"),
                "model_family": dry_evidence.get("model_family"),
                "validation_policy": dry_evidence.get("validation_policy"),
                "source_type": "dataset2_staging",
            },
            "metrics_review": {
                "baseline_strategy": dry_metrics.get("baseline_strategy"),
                "majority_label": dry_metrics.get("majority_label"),
                "train_row_count": train_rows,
                "out_of_sample_row_count": out_rows,
                "out_of_sample_accuracy": accuracy,
                "planned_feature_count": dry_metrics.get("planned_feature_count"),
                "feature_missing_counts": dry_metrics.get("feature_missing_counts") or {},
                "model_artifact_written": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_plan"
                    if accepted
                    else "resolve_dataset2_training_dry_run_review_blocks"
                ),
            },
            "decision": {
                "dataset2_training_dry_run_review_recorded": True,
                "dataset2_training_dry_run_review_accepted": accepted,
                "can_prepare_controlled_dataset2_training_execution_plan_now": accepted,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_plan"
                    if accepted
                    else "resolve_dataset2_training_dry_run_review_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_training_dry_run_review_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

