    def dataset2_controlled_training_execution_plan(
        self,
        dry_run_review_id: int | None = None,
        planned_by: str = "operator",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Create a non-executing controlled Dataset2 training execution plan after P67 review."""
        store = SQLiteStore(settings.database_path)
        store.init()
        review = self._dataset2_training_dry_run_review_by_id(store, dry_run_review_id)
        review_decision = (review or {}).get("decision") or {}
        review_evidence = (review or {}).get("evidence") or {}
        metrics_review = (review or {}).get("metrics_review") or {}
        review_ready = (
            review
            and review.get("status") == "dataset2_training_dry_run_review_accepted"
            and review_decision.get("dataset2_training_dry_run_review_accepted") is True
            and review_decision.get("can_prepare_controlled_dataset2_training_execution_plan_now") is True
        )
        plan_id = f"dataset2-controlled-training-plan-{self._stable_hash({'review_id': (review or {}).get('id'), 'sample_set_hash': review_evidence.get('sample_set_hash'), 'training_plan_id': review_evidence.get('training_plan_id')})[:16]}"
        plan_hash = self._stable_hash(
            {
                "plan_id": plan_id,
                "dry_run_review_id": (review or {}).get("id"),
                "sample_set_hash": review_evidence.get("sample_set_hash"),
                "metrics": metrics_review,
            }
        )
        checks = [
            self._manual_evidence_check(
                "dry_run_review_accepted",
                "passed" if review_ready else "blocked",
                {
                    "dry_run_review_id": (review or {}).get("id"),
                    "review_status": (review or {}).get("status"),
                    "can_prepare_controlled_dataset2_training_execution_plan_now": review_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_plan_now"
                    ),
                },
                "accepted P67 review",
                "P68 can only plan controlled training after accepted P67 dry-run review",
            ),
            self._manual_evidence_check(
                "sample_set_hash_pinned",
                "passed" if bool(review_evidence.get("sample_set_hash")) else "blocked",
                review_evidence.get("sample_set_hash"),
                "non-empty sample_set_hash",
                "Controlled training plan must pin the Dataset2 sample set hash",
            ),
            self._manual_evidence_check(
                "baseline_metrics_available",
                "passed" if metrics_review.get("out_of_sample_accuracy") is not None else "blocked",
                {
                    "out_of_sample_accuracy": metrics_review.get("out_of_sample_accuracy"),
                    "train_row_count": metrics_review.get("train_row_count"),
                    "out_of_sample_row_count": metrics_review.get("out_of_sample_row_count"),
                },
                "baseline metric and row counts",
                "Controlled training plan must carry forward P67 baseline metrics",
            ),
            self._manual_evidence_check(
                "no_model_artifact_or_training_started",
                (
                    "passed"
                    if review_decision.get("model_artifact_written") is False
                    and review_decision.get("training_started_now") is False
                    else "blocked"
                ),
                {
                    "model_artifact_written": review_decision.get("model_artifact_written"),
                    "training_started_now": review_decision.get("training_started_now"),
                },
                "all false",
                "P68 must start from a no-artifact, no-training review state",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training execution planning cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        ready = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_plan.v1",
            "stage": "V5.6-P68",
            "status": (
                "dataset2_controlled_training_execution_plan_ready"
                if ready
                else "dataset2_controlled_training_execution_plan_blocked"
            ),
            "generated_at": now,
            "package_id": (review or {}).get("package_id"),
            "planning": {
                "planned_by": planned_by or "operator",
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "dry_run_review_id": (review or {}).get("id"),
                "dry_run_event_id": review_evidence.get("dry_run_event_id"),
                "approval_event_id": review_evidence.get("approval_event_id"),
                "training_plan_event_id": review_evidence.get("training_plan_event_id"),
                "training_plan_id": review_evidence.get("training_plan_id"),
                "sample_set_hash": review_evidence.get("sample_set_hash"),
                "learning_sample_count": review_evidence.get("learning_sample_count"),
                "source_type": "dataset2_staging",
            },
            "execution_plan": {
                "plan_id": plan_id,
                "plan_hash": plan_hash,
                "model_family": review_evidence.get("model_family") or "local_rule_classifier",
                "validation_policy": review_evidence.get("validation_policy"),
                "baseline_accuracy": metrics_review.get("out_of_sample_accuracy"),
                "train_row_count": metrics_review.get("train_row_count"),
                "out_of_sample_row_count": metrics_review.get("out_of_sample_row_count"),
                "required_preflight_checks": [
                    "sample_set_hash_matches",
                    "learning_sample_count_matches",
                    "live_trading_disabled",
                    "no_existing_model_artifact_write",
                    "explicit_execution_token_required",
                    "result_review_required",
                ],
                "expected_confirmation_token": "PREPARE_DATASET2_CONTROLLED_TRAINING_EXECUTION",
                "writes_model_artifact_now": False,
                "executes_training_now": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "request_controlled_dataset2_training_execution_preflight"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_plan_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_plan_recorded": True,
                "controlled_dataset2_training_execution_plan_ready": ready,
                "can_prepare_controlled_dataset2_training_execution_preflight_now": ready,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "request_controlled_dataset2_training_execution_preflight"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_plan_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_plan_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

