    def dataset2_controlled_training_execution_preflight(
        self,
        execution_plan_id: str | None = None,
        execution_plan_event_id: int | None = None,
        requested_by: str = "operator",
        confirmation_token: str | None = None,
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Preflight a controlled Dataset2 training execution plan without executing training."""
        store = SQLiteStore(settings.database_path)
        store.init()
        plan = self._dataset2_controlled_training_execution_plan_by_id_or_plan_id(
            store,
            event_id=execution_plan_event_id,
            plan_id=execution_plan_id,
        )
        plan_decision = (plan or {}).get("decision") or {}
        plan_evidence = (plan or {}).get("evidence") or {}
        execution_plan = (plan or {}).get("execution_plan") or {}
        resolved_package_id = (plan or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("source_id") or row.get("id") or "") for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids)
        expected_token = execution_plan.get("expected_confirmation_token") or "PREPARE_DATASET2_CONTROLLED_TRAINING_EXECUTION"
        plan_ready = (
            plan
            and plan.get("status") == "dataset2_controlled_training_execution_plan_ready"
            and plan_decision.get("controlled_dataset2_training_execution_plan_ready") is True
            and plan_decision.get("can_prepare_controlled_dataset2_training_execution_preflight_now") is True
        )
        checks = [
            self._manual_evidence_check(
                "controlled_training_execution_plan_ready",
                "passed" if plan_ready else "blocked",
                {
                    "execution_plan_event_id": (plan or {}).get("id"),
                    "requested_execution_plan_id": execution_plan_id,
                    "resolved_execution_plan_id": execution_plan.get("plan_id"),
                    "plan_status": (plan or {}).get("status"),
                    "can_prepare_preflight": plan_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_preflight_now"
                    ),
                },
                "ready P68 controlled training execution plan",
                "P69 can only run after a ready P68 plan",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P69 requires explicit confirmation before preflighting controlled training execution",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_plan",
                (
                    "passed"
                    if rows and current_sample_set_hash == plan_evidence.get("sample_set_hash")
                    else "blocked"
                ),
                {
                    "current_sample_set_hash": current_sample_set_hash,
                    "planned_sample_set_hash": plan_evidence.get("sample_set_hash"),
                },
                "matching sample_set_hash",
                "Preflight must pin to the same Dataset2 sample set as P68",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_plan",
                (
                    "passed"
                    if rows and len(rows) == plan_evidence.get("learning_sample_count")
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "planned_learning_sample_count": plan_evidence.get("learning_sample_count"),
                },
                "current count equals P68 planned count",
                "Preflight must verify the promoted Dataset2 sample count has not drifted",
            ),
            self._manual_evidence_check(
                "plan_hash_present",
                "passed" if bool(execution_plan.get("plan_hash")) else "blocked",
                execution_plan.get("plan_hash"),
                "non-empty plan_hash",
                "Preflight must pin to a deterministic P68 plan hash",
            ),
            self._manual_evidence_check(
                "no_model_artifact_or_training_started",
                (
                    "passed"
                    if plan_decision.get("model_artifact_written") is False
                    and plan_decision.get("training_started_now") is False
                    and execution_plan.get("writes_model_artifact_now") is False
                    and execution_plan.get("executes_training_now") is False
                    else "blocked"
                ),
                {
                    "decision_model_artifact_written": plan_decision.get("model_artifact_written"),
                    "decision_training_started_now": plan_decision.get("training_started_now"),
                    "plan_writes_model_artifact_now": execution_plan.get("writes_model_artifact_now"),
                    "plan_executes_training_now": execution_plan.get("executes_training_now"),
                },
                "all false",
                "P69 must confirm P68 did not write artifacts or execute training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training preflight cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        ready = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_preflight.v1",
            "stage": "V5.6-P69",
            "status": (
                "dataset2_controlled_training_execution_preflight_ready"
                if ready
                else "dataset2_controlled_training_execution_preflight_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "preflight": {
                "requested_by": requested_by or "operator",
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "execution_plan_event_id": (plan or {}).get("id"),
                "execution_plan_id": execution_plan.get("plan_id"),
                "execution_plan_hash": execution_plan.get("plan_hash"),
                "dry_run_review_id": plan_evidence.get("dry_run_review_id"),
                "dry_run_event_id": plan_evidence.get("dry_run_event_id"),
                "training_plan_id": plan_evidence.get("training_plan_id"),
                "planned_sample_set_hash": plan_evidence.get("sample_set_hash"),
                "current_sample_set_hash": current_sample_set_hash,
                "planned_learning_sample_count": plan_evidence.get("learning_sample_count"),
                "current_learning_sample_count": len(rows),
                "source_type": "dataset2_staging",
            },
            "execution_preflight": {
                "required_checks": execution_plan.get("required_preflight_checks") or [],
                "baseline_accuracy": execution_plan.get("baseline_accuracy"),
                "model_family": execution_plan.get("model_family"),
                "validation_policy": execution_plan.get("validation_policy"),
                "can_run_training_dry_execution_now": ready,
                "writes_model_artifact_now": False,
                "executes_training_now": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_dry_run"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_preflight_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_preflight_recorded": True,
                "controlled_dataset2_training_execution_preflight_ready": ready,
                "can_prepare_controlled_dataset2_training_execution_dry_run_now": ready,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_dry_run"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_preflight_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_preflight_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

    def list_dataset2_controlled_training_execution_preflights(self, limit: int = 20) -> list[dict[str, Any]]:
        store = SQLiteStore(settings.database_path)
        store.init()
        rows = store.fetch_all(
            """
            SELECT id, event_type, payload_json, created_at
            FROM events
            WHERE event_type = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (self.dataset2_controlled_training_execution_preflight_event_type, max(1, min(limit, 100))),
        )
        return [self._event_payload(row) for row in rows]

    def dataset2_controlled_training_execution_dry_run(
        self,
        preflight_event_id: int | None = None,
        simulated_by: str = "operator",
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Simulate controlled Dataset2 training execution without training or writing artifacts."""
        store = SQLiteStore(settings.database_path)
        store.init()
        preflight = self._dataset2_controlled_training_execution_preflight_by_id(store, preflight_event_id)
        preflight_decision = (preflight or {}).get("decision") or {}
        preflight_evidence = (preflight or {}).get("evidence") or {}
        execution_preflight = (preflight or {}).get("execution_preflight") or {}
        resolved_package_id = (preflight or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("source_id") or row.get("id") or "") for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids)
        label_counts: Counter[str] = Counter()
        split_counts: Counter[str] = Counter()
        risk_counts: Counter[str] = Counter()
        for row in rows:
            features = json.loads(row.get("features_json") or "{}")
            label_counts[str(row.get("label") or "unknown")] += 1
            split_counts[str(features.get("split_tag") or "unknown")] += 1
            risk_counts[str(row.get("risk_level") or "unknown")] += 1
        preflight_ready = (
            preflight
            and preflight.get("status") == "dataset2_controlled_training_execution_preflight_ready"
            and preflight_decision.get("controlled_dataset2_training_execution_preflight_ready") is True
            and preflight_decision.get("can_prepare_controlled_dataset2_training_execution_dry_run_now") is True
        )
        simulated_manifest = {
            "manifest_kind": "dataset2_training_execution_dry_run_manifest",
            "execution_plan_id": preflight_evidence.get("execution_plan_id"),
            "execution_plan_hash": preflight_evidence.get("execution_plan_hash"),
            "sample_set_hash": current_sample_set_hash,
            "learning_sample_count": len(rows),
            "model_family": execution_preflight.get("model_family"),
            "validation_policy": execution_preflight.get("validation_policy"),
            "baseline_accuracy": execution_preflight.get("baseline_accuracy"),
            "would_write_model_artifact": False,
            "would_write_file": False,
            "would_execute_real_training": False,
        }
        manifest_hash = self._stable_hash(simulated_manifest)
        checks = [
            self._manual_evidence_check(
                "controlled_training_execution_preflight_ready",
                "passed" if preflight_ready else "blocked",
                {
                    "preflight_event_id": (preflight or {}).get("id"),
                    "preflight_status": (preflight or {}).get("status"),
                    "can_prepare_dry_run": preflight_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_dry_run_now"
                    ),
                },
                "ready P69 preflight",
                "P70 can only run after a ready P69 controlled training preflight",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_preflight",
                (
                    "passed"
                    if rows and current_sample_set_hash == preflight_evidence.get("current_sample_set_hash")
                    else "blocked"
                ),
                {
                    "current_sample_set_hash": current_sample_set_hash,
                    "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                },
                "matching sample_set_hash",
                "P70 dry-run must simulate the same Dataset2 sample set as P69",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_preflight",
                (
                    "passed"
                    if rows and len(rows) == preflight_evidence.get("current_learning_sample_count")
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                },
                "current count equals P69 count",
                "P70 dry-run must verify the Dataset2 sample count has not drifted",
            ),
            self._manual_evidence_check(
                "simulated_manifest_hash_recorded",
                "passed" if bool(manifest_hash) else "blocked",
                manifest_hash,
                "non-empty manifest hash",
                "P70 must produce deterministic manifest metadata for later review",
            ),
            self._manual_evidence_check(
                "no_model_artifact_or_training_started",
                (
                    "passed"
                    if preflight_decision.get("model_artifact_written") is False
                    and preflight_decision.get("training_started_now") is False
                    and execution_preflight.get("writes_model_artifact_now") is False
                    and execution_preflight.get("executes_training_now") is False
                    else "blocked"
                ),
                {
                    "decision_model_artifact_written": preflight_decision.get("model_artifact_written"),
                    "decision_training_started_now": preflight_decision.get("training_started_now"),
                    "preflight_writes_model_artifact_now": execution_preflight.get("writes_model_artifact_now"),
                    "preflight_executes_training_now": execution_preflight.get("executes_training_now"),
                },
                "all false",
                "P70 must not inherit any artifact or real training execution state",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training dry-run cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        completed = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_dry_run.v1",
            "stage": "V5.6-P70",
            "status": (
                "dataset2_controlled_training_execution_dry_run_completed"
                if completed
                else "dataset2_controlled_training_execution_dry_run_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "dry_run": {
                "simulated_by": simulated_by or "operator",
                "note": note,
                "record_bodies_included": False,
                "model_artifact_written": False,
                "writes_file": False,
                "executes_training_now": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "preflight_event_id": (preflight or {}).get("id"),
                "execution_plan_event_id": preflight_evidence.get("execution_plan_event_id"),
                "execution_plan_id": preflight_evidence.get("execution_plan_id"),
                "execution_plan_hash": preflight_evidence.get("execution_plan_hash"),
                "training_plan_id": preflight_evidence.get("training_plan_id"),
                "current_sample_set_hash": current_sample_set_hash,
                "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                "learning_sample_count": len(rows),
                "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                "source_type": "dataset2_staging",
            },
            "simulation_result": {
                "manifest": simulated_manifest,
                "manifest_hash": manifest_hash,
                "label_counts": dict(label_counts),
                "split_counts": dict(split_counts),
                "risk_level_counts": dict(risk_counts),
                "baseline_accuracy": execution_preflight.get("baseline_accuracy"),
                "model_family": execution_preflight.get("model_family"),
                "validation_policy": execution_preflight.get("validation_policy"),
                "would_write_model_artifact": False,
                "would_write_file": False,
                "would_execute_training": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_dry_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_dry_run_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_dry_run_recorded": True,
                "controlled_dataset2_training_execution_dry_run_completed": completed,
                "can_prepare_controlled_dataset2_training_execution_dry_run_review_now": completed,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_dry_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_dry_run_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_dry_run_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

    def list_dataset2_controlled_training_execution_dry_runs(self, limit: int = 20) -> list[dict[str, Any]]:
        store = SQLiteStore(settings.database_path)
