    def dataset2_controlled_training_execution_dry_run_review(
        self,
        dry_run_event_id: int | None = None,
        reviewed_by: str = "operator",
        review_decision: str = "accepted_for_controlled_dataset2_training_execution_release_plan",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Review P70 controlled training dry-run evidence before any release plan is prepared."""
        store = SQLiteStore(settings.database_path)
        store.init()
        dry_run = self._dataset2_controlled_training_execution_dry_run_by_id(store, dry_run_event_id)
        dry_decision = (dry_run or {}).get("decision") or {}
        dry_evidence = (dry_run or {}).get("evidence") or {}
        simulation_result = (dry_run or {}).get("simulation_result") or {}
        manifest = simulation_result.get("manifest") or {}
        allowed_decision = "accepted_for_controlled_dataset2_training_execution_release_plan"
        dry_run_completed = (
            dry_run
            and dry_run.get("status") == "dataset2_controlled_training_execution_dry_run_completed"
            and dry_decision.get("controlled_dataset2_training_execution_dry_run_completed") is True
            and dry_decision.get("can_prepare_controlled_dataset2_training_execution_dry_run_review_now") is True
        )
        no_execution_or_artifact = (
            simulation_result.get("would_write_model_artifact") is False
            and simulation_result.get("would_write_file") is False
            and simulation_result.get("would_execute_training") is False
            and simulation_result.get("training_started_now") is False
            and dry_decision.get("model_artifact_written") is False
            and dry_decision.get("writes_file") is False
            and dry_decision.get("training_started_now") is False
            and dry_decision.get("can_execute_dataset2_training_now") is False
        )
        sample_count = int(dry_evidence.get("learning_sample_count") or 0)
        label_counts = simulation_result.get("label_counts") or {}
        split_counts = simulation_result.get("split_counts") or {}
        risk_counts = simulation_result.get("risk_level_counts") or {}
        checks = [
            self._manual_evidence_check(
                "controlled_training_execution_dry_run_completed",
                "passed" if dry_run_completed else "blocked",
                {
                    "dry_run_event_id": (dry_run or {}).get("id"),
                    "dry_run_status": (dry_run or {}).get("status"),
                    "can_prepare_review": dry_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_dry_run_review_now"
                    ),
                },
                "completed P70 dry-run",
                "P71 can only review completed P70 controlled training dry-run evidence",
            ),
            self._manual_evidence_check(
                "review_decision_allowed",
                "passed" if review_decision == allowed_decision else "blocked",
                review_decision,
                allowed_decision,
                "P71 review can only accept evidence for a later controlled release plan",
            ),
            self._manual_evidence_check(
                "manifest_hash_recorded",
                "passed" if bool(simulation_result.get("manifest_hash")) else "blocked",
                simulation_result.get("manifest_hash"),
                "non-empty manifest_hash",
                "P71 must pin review evidence to the P70 simulated execution manifest",
            ),
            self._manual_evidence_check(
                "sample_set_hash_recorded",
                "passed" if bool(dry_evidence.get("current_sample_set_hash") or manifest.get("sample_set_hash")) else "blocked",
                {
                    "evidence_sample_set_hash": dry_evidence.get("current_sample_set_hash"),
                    "manifest_sample_set_hash": manifest.get("sample_set_hash"),
                },
                "non-empty sample_set_hash",
                "P71 must preserve Dataset2 sample-set traceability before release planning",
            ),
            self._manual_evidence_check(
                "learning_sample_distribution_present",
                "passed" if sample_count > 0 and bool(label_counts) and bool(split_counts) else "blocked",
                {
                    "learning_sample_count": sample_count,
                    "label_counts": label_counts,
                    "split_counts": split_counts,
                    "risk_level_counts": risk_counts,
                },
                "samples with label and split distributions",
                "P71 review needs aggregate distribution evidence without record bodies",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "would_write_model_artifact": simulation_result.get("would_write_model_artifact"),
                    "would_write_file": simulation_result.get("would_write_file"),
                    "would_execute_training": simulation_result.get("would_execute_training"),
                    "training_started_now": simulation_result.get("training_started_now"),
                    "decision_model_artifact_written": dry_decision.get("model_artifact_written"),
                    "decision_writes_file": dry_decision.get("writes_file"),
                    "decision_can_execute_training_now": dry_decision.get("can_execute_dataset2_training_now"),
                },
                "all false",
                "P71 must confirm P70 did not write files, write model artifacts, or execute training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training dry-run review cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_dry_run_review.v1",
            "stage": "V5.6-P71",
            "status": (
                "dataset2_controlled_training_execution_dry_run_review_accepted"
                if accepted
                else "dataset2_controlled_training_execution_dry_run_review_blocked"
            ),
            "generated_at": now,
            "package_id": (dry_run or {}).get("package_id"),
            "review": {
                "reviewed_by": reviewed_by or "operator",
                "review_decision": review_decision,
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "dry_run_event_id": (dry_run or {}).get("id"),
                "preflight_event_id": dry_evidence.get("preflight_event_id"),
                "execution_plan_event_id": dry_evidence.get("execution_plan_event_id"),
                "execution_plan_id": dry_evidence.get("execution_plan_id"),
                "execution_plan_hash": dry_evidence.get("execution_plan_hash"),
                "training_plan_id": dry_evidence.get("training_plan_id"),
                "manifest_hash": simulation_result.get("manifest_hash"),
                "sample_set_hash": dry_evidence.get("current_sample_set_hash") or manifest.get("sample_set_hash"),
                "learning_sample_count": sample_count,
                "source_type": "dataset2_staging",
            },
            "manifest_review": {
                "manifest_kind": manifest.get("manifest_kind"),
                "model_family": simulation_result.get("model_family") or manifest.get("model_family"),
                "validation_policy": simulation_result.get("validation_policy") or manifest.get("validation_policy"),
                "baseline_accuracy": simulation_result.get("baseline_accuracy") or manifest.get("baseline_accuracy"),
                "label_counts": label_counts,
                "split_counts": split_counts,
                "risk_level_counts": risk_counts,
                "would_write_model_artifact": False,
                "would_write_file": False,
                "would_execute_training": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_release_plan"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_dry_run_review_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_dry_run_review_recorded": True,
                "controlled_dataset2_training_execution_dry_run_review_accepted": accepted,
                "can_prepare_controlled_dataset2_training_execution_release_plan_now": accepted,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_release_plan"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_dry_run_review_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_dry_run_review_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

