    def dataset2_controlled_training_execution_release_plan(
        self,
        dry_run_review_id: int | None = None,
        planned_by: str = "operator",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Create a metadata-only Dataset2 controlled training release plan after P71 review."""
        store = SQLiteStore(settings.database_path)
        store.init()
        review = self._dataset2_controlled_training_execution_dry_run_review_by_id(store, dry_run_review_id)
        review_decision = (review or {}).get("decision") or {}
        review_evidence = (review or {}).get("evidence") or {}
        manifest_review = (review or {}).get("manifest_review") or {}
        review_ready = (
            review
            and review.get("status") == "dataset2_controlled_training_execution_dry_run_review_accepted"
            and review_decision.get("controlled_dataset2_training_execution_dry_run_review_accepted") is True
            and review_decision.get("can_prepare_controlled_dataset2_training_execution_release_plan_now") is True
        )
        plan_seed = {
            "dry_run_review_id": (review or {}).get("id"),
            "manifest_hash": review_evidence.get("manifest_hash"),
            "sample_set_hash": review_evidence.get("sample_set_hash"),
            "execution_plan_id": review_evidence.get("execution_plan_id"),
        }
        release_plan_id = f"dataset2-controlled-training-release-{self._stable_hash(plan_seed)[:16]}"
        release_plan = {
            "plan_id": release_plan_id,
            "plan_hash_inputs": plan_seed,
            "source_stage": "V5.6-P71",
            "release_scope": "dataset2_controlled_training_execution",
            "model_family": manifest_review.get("model_family") or "local_rule_classifier",
            "validation_policy": manifest_review.get("validation_policy"),
            "baseline_accuracy": manifest_review.get("baseline_accuracy"),
            "learning_sample_count": review_evidence.get("learning_sample_count"),
            "required_manual_approval_steps": [
                "review_p70_manifest_hash",
                "review_dataset2_sample_set_hash",
                "review_label_split_risk_distribution",
                "confirm_no_model_artifact_or_file_written",
                "confirm_live_trading_disabled",
                "approve_later_release_preflight_only",
            ],
            "required_preflight_checks": [
                "p71_review_still_latest_or_explicitly_selected",
                "sample_set_hash_matches_p71",
                "manifest_hash_matches_p71",
                "learning_sample_count_matches_p71",
                "live_trading_disabled",
                "no_existing_model_artifact_write",
                "explicit_release_preflight_token_required",
            ],
            "expected_confirmation_token": "PREPARE_DATASET2_CONTROLLED_TRAINING_RELEASE_PREFLIGHT",
            "writes_model_artifact_now": False,
            "writes_file_now": False,
            "executes_training_now": False,
            "training_started_now": False,
        }
        release_plan_hash = self._stable_hash(release_plan)
        release_plan["plan_hash"] = release_plan_hash
        distribution_ready = (
            bool(manifest_review.get("label_counts"))
            and bool(manifest_review.get("split_counts"))
            and int(review_evidence.get("learning_sample_count") or 0) > 0
        )
        no_execution_or_artifact = (
            manifest_review.get("would_write_model_artifact") is False
            and manifest_review.get("would_write_file") is False
            and manifest_review.get("would_execute_training") is False
            and manifest_review.get("training_started_now") is False
            and review_decision.get("model_artifact_written") is False
            and review_decision.get("writes_file") is False
            and review_decision.get("training_started_now") is False
            and review_decision.get("can_execute_dataset2_training_now") is False
        )
        checks = [
            self._manual_evidence_check(
                "dry_run_review_accepted_for_release_plan",
                "passed" if review_ready else "blocked",
                {
                    "dry_run_review_id": (review or {}).get("id"),
                    "review_status": (review or {}).get("status"),
                    "can_prepare_release_plan": review_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_release_plan_now"
                    ),
                },
                "accepted P71 review",
                "P72 can only plan release after accepted P71 controlled training dry-run review",
            ),
            self._manual_evidence_check(
                "manifest_hash_pinned",
                "passed" if bool(review_evidence.get("manifest_hash")) else "blocked",
                review_evidence.get("manifest_hash"),
                "non-empty manifest_hash",
                "P72 release plan must pin the P70 simulated execution manifest hash",
            ),
            self._manual_evidence_check(
                "sample_set_hash_pinned",
                "passed" if bool(review_evidence.get("sample_set_hash")) else "blocked",
                review_evidence.get("sample_set_hash"),
                "non-empty sample_set_hash",
                "P72 release plan must pin the Dataset2 sample-set hash",
            ),
            self._manual_evidence_check(
                "distribution_evidence_present",
                "passed" if distribution_ready else "blocked",
                {
                    "learning_sample_count": review_evidence.get("learning_sample_count"),
                    "label_counts": manifest_review.get("label_counts") or {},
                    "split_counts": manifest_review.get("split_counts") or {},
                    "risk_level_counts": manifest_review.get("risk_level_counts") or {},
                },
                "sample count and aggregate distributions",
                "P72 release planning needs aggregate learning-sample evidence without record bodies",
            ),
            self._manual_evidence_check(
                "release_plan_hash_recorded",
                "passed" if bool(release_plan_hash) else "blocked",
                release_plan_hash,
                "non-empty release plan hash",
                "P72 must create deterministic release plan metadata for later preflight",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "manifest_would_write_model_artifact": manifest_review.get("would_write_model_artifact"),
                    "manifest_would_write_file": manifest_review.get("would_write_file"),
                    "manifest_would_execute_training": manifest_review.get("would_execute_training"),
                    "manifest_training_started_now": manifest_review.get("training_started_now"),
                    "decision_model_artifact_written": review_decision.get("model_artifact_written"),
                    "decision_writes_file": review_decision.get("writes_file"),
                    "decision_can_execute_training_now": review_decision.get("can_execute_dataset2_training_now"),
                },
                "all false",
                "P72 must remain a release plan only and not execute training or write artifacts",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training release planning cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        ready = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_release_plan.v1",
            "stage": "V5.6-P72",
            "status": (
                "dataset2_controlled_training_execution_release_plan_ready"
                if ready
                else "dataset2_controlled_training_execution_release_plan_blocked"
            ),
            "generated_at": now,
            "package_id": (review or {}).get("package_id"),
            "planning": {
                "planned_by": planned_by or "operator",
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "dry_run_review_id": (review or {}).get("id"),
                "dry_run_event_id": review_evidence.get("dry_run_event_id"),
                "preflight_event_id": review_evidence.get("preflight_event_id"),
                "execution_plan_event_id": review_evidence.get("execution_plan_event_id"),
                "execution_plan_id": review_evidence.get("execution_plan_id"),
                "execution_plan_hash": review_evidence.get("execution_plan_hash"),
                "training_plan_id": review_evidence.get("training_plan_id"),
                "manifest_hash": review_evidence.get("manifest_hash"),
                "sample_set_hash": review_evidence.get("sample_set_hash"),
                "learning_sample_count": review_evidence.get("learning_sample_count"),
                "source_type": "dataset2_staging",
            },
            "release_plan": release_plan,
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_release_preflight"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_release_plan_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_release_plan_recorded": True,
                "controlled_dataset2_training_execution_release_plan_ready": ready,
                "can_prepare_controlled_dataset2_training_execution_release_preflight_now": ready,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_release_preflight"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_release_plan_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_release_plan_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

