    def dataset2_controlled_training_execution_release_preflight(
        self,
        release_plan_id: str | None = None,
        release_plan_event_id: int | None = None,
        requested_by: str = "operator",
        confirmation_token: str | None = None,
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Preflight a Dataset2 controlled training release plan without training or writing artifacts."""
        store = SQLiteStore(settings.database_path)
        store.init()
        plan = self._dataset2_controlled_training_execution_release_plan_by_id_or_plan_id(
            store,
            event_id=release_plan_event_id,
            plan_id=release_plan_id,
        )
        plan_decision = (plan or {}).get("decision") or {}
        plan_evidence = (plan or {}).get("evidence") or {}
        release_plan = (plan or {}).get("release_plan") or {}
        resolved_package_id = (plan or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("source_id") or row.get("id") or "") for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids)
        expected_token = (
            release_plan.get("expected_confirmation_token")
            or "PREPARE_DATASET2_CONTROLLED_TRAINING_RELEASE_PREFLIGHT"
        )
        plan_ready = (
            plan
            and plan.get("status") == "dataset2_controlled_training_execution_release_plan_ready"
            and plan_decision.get("controlled_dataset2_training_execution_release_plan_ready") is True
            and plan_decision.get("can_prepare_controlled_dataset2_training_execution_release_preflight_now") is True
        )
        plan_hash_inputs = release_plan.get("plan_hash_inputs") or {}
        no_execution_or_artifact = (
            plan_decision.get("model_artifact_written") is False
            and plan_decision.get("training_started_now") is False
            and plan_decision.get("writes_file") is False
            and plan_decision.get("can_execute_dataset2_training_now") is False
            and release_plan.get("writes_model_artifact_now") is False
            and release_plan.get("writes_file_now") is False
            and release_plan.get("executes_training_now") is False
            and release_plan.get("training_started_now") is False
        )
        checks = [
            self._manual_evidence_check(
                "controlled_training_execution_release_plan_ready",
                "passed" if plan_ready else "blocked",
                {
                    "release_plan_event_id": (plan or {}).get("id"),
                    "requested_release_plan_id": release_plan_id,
                    "resolved_release_plan_id": release_plan.get("plan_id"),
                    "plan_status": (plan or {}).get("status"),
                    "can_prepare_release_preflight": plan_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_release_preflight_now"
                    ),
                },
                "ready P72 release plan",
                "P73 can only run after a ready P72 controlled training release plan",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P73 requires explicit confirmation before release preflight",
            ),
            self._manual_evidence_check(
                "release_plan_hash_present",
                "passed" if bool(release_plan.get("plan_hash")) else "blocked",
                release_plan.get("plan_hash"),
                "non-empty plan_hash",
                "Release preflight must pin to a deterministic P72 release plan hash",
            ),
            self._manual_evidence_check(
                "manifest_hash_matches_release_plan",
                (
                    "passed"
                    if bool(plan_evidence.get("manifest_hash"))
                    and plan_evidence.get("manifest_hash") == plan_hash_inputs.get("manifest_hash")
                    else "blocked"
                ),
                {
                    "evidence_manifest_hash": plan_evidence.get("manifest_hash"),
                    "plan_input_manifest_hash": plan_hash_inputs.get("manifest_hash"),
                },
                "matching manifest hash",
                "P73 must preserve P70/P71 simulated manifest traceability",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_release_plan",
                (
                    "passed"
                    if rows and current_sample_set_hash == plan_evidence.get("sample_set_hash")
                    else "blocked"
                ),
                {
                    "current_sample_set_hash": current_sample_set_hash,
                    "planned_sample_set_hash": plan_evidence.get("sample_set_hash"),
                },
                "matching sample_set_hash",
                "Release preflight must verify the Dataset2 sample set has not drifted since P72",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_release_plan",
                (
                    "passed"
                    if rows and len(rows) == plan_evidence.get("learning_sample_count")
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "planned_learning_sample_count": plan_evidence.get("learning_sample_count"),
                },
                "current count equals P72 planned count",
                "Release preflight must verify the Dataset2 sample count has not drifted",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "decision_model_artifact_written": plan_decision.get("model_artifact_written"),
                    "decision_training_started_now": plan_decision.get("training_started_now"),
                    "decision_writes_file": plan_decision.get("writes_file"),
                    "decision_can_execute_training_now": plan_decision.get("can_execute_dataset2_training_now"),
                    "plan_writes_model_artifact_now": release_plan.get("writes_model_artifact_now"),
                    "plan_writes_file_now": release_plan.get("writes_file_now"),
                    "plan_executes_training_now": release_plan.get("executes_training_now"),
                },
                "all false",
                "P73 must confirm P72 did not write artifacts, write files, or execute training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training release preflight cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        ready = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_release_preflight.v1",
            "stage": "V5.6-P73",
            "status": (
                "dataset2_controlled_training_execution_release_preflight_ready"
                if ready
                else "dataset2_controlled_training_execution_release_preflight_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "preflight": {
                "requested_by": requested_by or "operator",
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "release_plan_event_id": (plan or {}).get("id"),
                "release_plan_id": release_plan.get("plan_id"),
                "release_plan_hash": release_plan.get("plan_hash"),
                "dry_run_review_id": plan_evidence.get("dry_run_review_id"),
                "dry_run_event_id": plan_evidence.get("dry_run_event_id"),
                "preflight_event_id": plan_evidence.get("preflight_event_id"),
                "execution_plan_event_id": plan_evidence.get("execution_plan_event_id"),
                "execution_plan_id": plan_evidence.get("execution_plan_id"),
                "training_plan_id": plan_evidence.get("training_plan_id"),
                "manifest_hash": plan_evidence.get("manifest_hash"),
                "planned_sample_set_hash": plan_evidence.get("sample_set_hash"),
                "current_sample_set_hash": current_sample_set_hash,
                "planned_learning_sample_count": plan_evidence.get("learning_sample_count"),
                "current_learning_sample_count": len(rows),
                "source_type": "dataset2_staging",
            },
            "release_preflight": {
                "required_checks": release_plan.get("required_preflight_checks") or [],
                "required_manual_approval_steps": release_plan.get("required_manual_approval_steps") or [],
                "baseline_accuracy": release_plan.get("baseline_accuracy"),
                "model_family": release_plan.get("model_family"),
                "validation_policy": release_plan.get("validation_policy"),
                "can_prepare_controlled_dataset2_training_execution_release_dry_run_now": ready,
                "writes_model_artifact_now": False,
                "writes_file_now": False,
                "executes_training_now": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_release_dry_run"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_release_preflight_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_release_preflight_recorded": True,
                "controlled_dataset2_training_execution_release_preflight_ready": ready,
                "can_prepare_controlled_dataset2_training_execution_release_dry_run_now": ready,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_release_dry_run"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_release_preflight_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_release_preflight_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

