    def dataset2_controlled_training_execution_release_dry_run(
        self,
        release_preflight_event_id: int | None = None,
        simulated_by: str = "operator",
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Simulate Dataset2 controlled training release execution without training or artifact writes."""
        store = SQLiteStore(settings.database_path)
        store.init()
        preflight = self._dataset2_controlled_training_execution_release_preflight_by_id(
            store,
            release_preflight_event_id,
        )
        preflight_decision = (preflight or {}).get("decision") or {}
        preflight_evidence = (preflight or {}).get("evidence") or {}
        release_preflight = (preflight or {}).get("release_preflight") or {}
        resolved_package_id = (preflight or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("source_id") or row.get("id") or "") for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids)
        label_counts: Counter[str] = Counter()
        split_counts: Counter[str] = Counter()
        risk_counts: Counter[str] = Counter()
        feature_key_counts: Counter[str] = Counter()
        for row in rows:
            features = json.loads(row.get("features_json") or "{}")
            label_counts[str(row.get("label") or "unknown")] += 1
            split_counts[str(features.get("split_tag") or "unknown")] += 1
            risk_counts[str(row.get("risk_level") or "unknown")] += 1
            for key in features.keys():
                feature_key_counts[str(key)] += 1
        preflight_ready = (
            preflight
            and preflight.get("status") == "dataset2_controlled_training_execution_release_preflight_ready"
            and preflight_decision.get("controlled_dataset2_training_execution_release_preflight_ready") is True
            and preflight_decision.get("can_prepare_controlled_dataset2_training_execution_release_dry_run_now") is True
        )
        artifact_manifest = {
            "artifact_kind": "dataset2_controlled_training_release_model_artifact_manifest",
            "artifact_write_allowed": False,
            "artifact_path": None,
            "model_family": release_preflight.get("model_family"),
            "validation_policy": release_preflight.get("validation_policy"),
            "sample_set_hash": current_sample_set_hash,
            "release_plan_hash": preflight_evidence.get("release_plan_hash"),
            "manifest_hash": preflight_evidence.get("manifest_hash"),
            "learning_sample_count": len(rows),
            "label_counts": dict(label_counts),
            "split_counts": dict(split_counts),
            "risk_level_counts": dict(risk_counts),
        }
        artifact_manifest_hash = self._stable_hash(artifact_manifest)
        release_simulation_manifest = {
            "manifest_kind": "dataset2_controlled_training_release_dry_run_manifest",
            "release_plan_event_id": preflight_evidence.get("release_plan_event_id"),
            "release_plan_id": preflight_evidence.get("release_plan_id"),
            "release_plan_hash": preflight_evidence.get("release_plan_hash"),
            "release_preflight_event_id": (preflight or {}).get("id"),
            "manifest_hash": preflight_evidence.get("manifest_hash"),
            "sample_set_hash": current_sample_set_hash,
            "learning_sample_count": len(rows),
            "model_family": release_preflight.get("model_family"),
            "validation_policy": release_preflight.get("validation_policy"),
            "baseline_accuracy": release_preflight.get("baseline_accuracy"),
            "artifact_manifest_hash": artifact_manifest_hash,
            "would_write_model_artifact": False,
            "would_write_file": False,
            "would_execute_real_training": False,
        }
        release_simulation_manifest_hash = self._stable_hash(release_simulation_manifest)
        no_execution_or_artifact = (
            preflight_decision.get("model_artifact_written") is False
            and preflight_decision.get("training_started_now") is False
            and preflight_decision.get("writes_file") is False
            and preflight_decision.get("can_execute_dataset2_training_now") is False
            and release_preflight.get("writes_model_artifact_now") is False
            and release_preflight.get("writes_file_now") is False
            and release_preflight.get("executes_training_now") is False
            and release_preflight.get("training_started_now") is False
        )
        checks = [
            self._manual_evidence_check(
                "release_preflight_ready",
                "passed" if preflight_ready else "blocked",
                {
                    "release_preflight_event_id": (preflight or {}).get("id"),
                    "release_preflight_status": (preflight or {}).get("status"),
                    "can_prepare_release_dry_run": preflight_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_release_dry_run_now"
                    ),
                },
                "ready P73 release preflight",
                "P74 can only run after a ready P73 controlled training release preflight",
            ),
            self._manual_evidence_check(
                "release_plan_hash_pinned",
                "passed" if bool(preflight_evidence.get("release_plan_hash")) else "blocked",
                preflight_evidence.get("release_plan_hash"),
                "non-empty release_plan_hash",
                "P74 must pin to a deterministic P72 release plan hash",
            ),
            self._manual_evidence_check(
                "manifest_hash_pinned",
                "passed" if bool(preflight_evidence.get("manifest_hash")) else "blocked",
                preflight_evidence.get("manifest_hash"),
                "non-empty manifest_hash",
                "P74 must preserve P70/P71 simulated manifest traceability",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_preflight",
                (
                    "passed"
                    if rows and current_sample_set_hash == preflight_evidence.get("current_sample_set_hash")
                    else "blocked"
                ),
                {
                    "current_sample_set_hash": current_sample_set_hash,
                    "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                },
                "matching sample_set_hash",
                "P74 dry-run must simulate the same Dataset2 sample set as P73",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_preflight",
                (
                    "passed"
                    if rows and len(rows) == preflight_evidence.get("current_learning_sample_count")
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                },
                "current count equals P73 count",
                "P74 dry-run must verify Dataset2 sample count has not drifted",
            ),
            self._manual_evidence_check(
                "simulated_artifact_manifest_hash_recorded",
                "passed" if bool(artifact_manifest_hash) else "blocked",
                artifact_manifest_hash,
                "non-empty artifact_manifest_hash",
                "P74 must produce deterministic artifact manifest metadata without writing the artifact",
            ),
            self._manual_evidence_check(
                "release_simulation_manifest_hash_recorded",
                "passed" if bool(release_simulation_manifest_hash) else "blocked",
                release_simulation_manifest_hash,
                "non-empty release_simulation_manifest_hash",
                "P74 must produce deterministic release dry-run metadata for later review",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "decision_model_artifact_written": preflight_decision.get("model_artifact_written"),
                    "decision_training_started_now": preflight_decision.get("training_started_now"),
                    "decision_writes_file": preflight_decision.get("writes_file"),
                    "decision_can_execute_training_now": preflight_decision.get("can_execute_dataset2_training_now"),
                    "preflight_writes_model_artifact_now": release_preflight.get("writes_model_artifact_now"),
                    "preflight_writes_file_now": release_preflight.get("writes_file_now"),
                    "preflight_executes_training_now": release_preflight.get("executes_training_now"),
                },
                "all false",
                "P74 must not write artifacts, write files, or execute training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training release dry-run cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        completed = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_release_dry_run.v1",
            "stage": "V5.6-P74",
            "status": (
                "dataset2_controlled_training_execution_release_dry_run_completed"
                if completed
                else "dataset2_controlled_training_execution_release_dry_run_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "dry_run": {
                "simulated_by": simulated_by or "operator",
                "note": note,
                "record_bodies_included": False,
                "model_artifact_written": False,
                "writes_file": False,
                "executes_training_now": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "release_preflight_event_id": (preflight or {}).get("id"),
                "release_plan_event_id": preflight_evidence.get("release_plan_event_id"),
                "release_plan_id": preflight_evidence.get("release_plan_id"),
                "release_plan_hash": preflight_evidence.get("release_plan_hash"),
                "dry_run_review_id": preflight_evidence.get("dry_run_review_id"),
                "dry_run_event_id": preflight_evidence.get("dry_run_event_id"),
                "manifest_hash": preflight_evidence.get("manifest_hash"),
                "current_sample_set_hash": current_sample_set_hash,
                "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                "learning_sample_count": len(rows),
                "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                "source_type": "dataset2_staging",
            },
            "simulation_result": {
                "release_simulation_manifest": release_simulation_manifest,
                "release_simulation_manifest_hash": release_simulation_manifest_hash,
                "artifact_manifest": artifact_manifest,
                "artifact_manifest_hash": artifact_manifest_hash,
                "label_counts": dict(label_counts),
                "split_counts": dict(split_counts),
                "risk_level_counts": dict(risk_counts),
                "feature_key_count": len(feature_key_counts),
                "baseline_accuracy": release_preflight.get("baseline_accuracy"),
                "model_family": release_preflight.get("model_family"),
                "validation_policy": release_preflight.get("validation_policy"),
                "would_write_model_artifact": False,
                "would_write_file": False,
                "would_execute_training": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_release_dry_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_release_dry_run_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_release_dry_run_recorded": True,
                "controlled_dataset2_training_execution_release_dry_run_completed": completed,
                "can_prepare_controlled_dataset2_training_execution_release_dry_run_review_now": completed,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_release_dry_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_release_dry_run_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_release_dry_run_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

    def list_dataset2_controlled_training_execution_release_dry_runs(
        self,
        limit: int = 20,
    ) -> list[dict[str, Any]]:
        store = SQLiteStore(settings.database_path)
        store.init()
        rows = store.fetch_all(
            """
            SELECT id, event_type, payload_json, created_at
            FROM events
            WHERE event_type = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (self.dataset2_controlled_training_execution_release_dry_run_event_type, max(1, min(limit, 100))),
        )
        return [self._event_payload(row) for row in rows]

    def dataset2_controlled_training_execution_release_dry_run_review(
        self,
        release_dry_run_event_id: int | None = None,
        reviewed_by: str = "operator",
        review_decision: str = "accepted_for_controlled_dataset2_training_execution_final_approval",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Review P74 release dry-run evidence before any final training approval is prepared."""
        store = SQLiteStore(settings.database_path)
        store.init()
        release_dry_run = self._dataset2_controlled_training_execution_release_dry_run_by_id(
            store,
            release_dry_run_event_id,
        )
        dry_decision = (release_dry_run or {}).get("decision") or {}
        dry_evidence = (release_dry_run or {}).get("evidence") or {}
        simulation_result = (release_dry_run or {}).get("simulation_result") or {}
        release_manifest = simulation_result.get("release_simulation_manifest") or {}
        artifact_manifest = simulation_result.get("artifact_manifest") or {}
        allowed_decision = "accepted_for_controlled_dataset2_training_execution_final_approval"
        release_dry_run_completed = (
            release_dry_run
            and release_dry_run.get("status")
            == "dataset2_controlled_training_execution_release_dry_run_completed"
            and dry_decision.get("controlled_dataset2_training_execution_release_dry_run_completed") is True
            and dry_decision.get(
                "can_prepare_controlled_dataset2_training_execution_release_dry_run_review_now"
            )
            is True
        )
        no_execution_or_artifact = (
            simulation_result.get("would_write_model_artifact") is False
            and simulation_result.get("would_write_file") is False
            and simulation_result.get("would_execute_training") is False
            and simulation_result.get("training_started_now") is False
            and artifact_manifest.get("artifact_write_allowed") is False
            and artifact_manifest.get("artifact_path") is None
            and dry_decision.get("model_artifact_written") is False
            and dry_decision.get("writes_file") is False
            and dry_decision.get("training_started_now") is False
            and dry_decision.get("can_execute_dataset2_training_now") is False
        )
        sample_count = int(dry_evidence.get("learning_sample_count") or 0)
        label_counts = simulation_result.get("label_counts") or {}
        split_counts = simulation_result.get("split_counts") or {}
        risk_counts = simulation_result.get("risk_level_counts") or {}
        sample_set_hash = dry_evidence.get("current_sample_set_hash") or release_manifest.get("sample_set_hash")
        checks = [
            self._manual_evidence_check(
                "release_dry_run_completed",
                "passed" if release_dry_run_completed else "blocked",
                {
                    "release_dry_run_event_id": (release_dry_run or {}).get("id"),
                    "release_dry_run_status": (release_dry_run or {}).get("status"),
                    "can_prepare_review": dry_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_release_dry_run_review_now"
                    ),
                },
                "completed P74 release dry-run",
                "P75 can only review completed P74 controlled training release dry-run evidence",
            ),
            self._manual_evidence_check(
                "review_decision_allowed",
                "passed" if review_decision == allowed_decision else "blocked",
                review_decision,
                allowed_decision,
                "P75 review can only accept evidence for a later final approval gate",
            ),
            self._manual_evidence_check(
                "release_simulation_manifest_hash_recorded",
                "passed" if bool(simulation_result.get("release_simulation_manifest_hash")) else "blocked",
                simulation_result.get("release_simulation_manifest_hash"),
                "non-empty release_simulation_manifest_hash",
                "P75 must pin review evidence to the P74 release simulation manifest",
            ),
            self._manual_evidence_check(
                "artifact_manifest_hash_recorded",
                "passed" if bool(simulation_result.get("artifact_manifest_hash")) else "blocked",
                simulation_result.get("artifact_manifest_hash"),
                "non-empty artifact_manifest_hash",
                "P75 must preserve the simulated model artifact manifest hash without writing it",
            ),
            self._manual_evidence_check(
                "sample_set_hash_recorded",
                "passed" if bool(sample_set_hash) else "blocked",
                {
                    "evidence_sample_set_hash": dry_evidence.get("current_sample_set_hash"),
                    "release_manifest_sample_set_hash": release_manifest.get("sample_set_hash"),
                },
                "non-empty sample_set_hash",
                "P75 must preserve Dataset2 sample-set traceability before final approval planning",
            ),
            self._manual_evidence_check(
                "learning_sample_distribution_present",
                "passed" if sample_count > 0 and bool(label_counts) and bool(split_counts) else "blocked",
                {
                    "learning_sample_count": sample_count,
                    "label_counts": label_counts,
                    "split_counts": split_counts,
                    "risk_level_counts": risk_counts,
                },
                "samples with label and split distributions",
                "P75 review needs aggregate distribution evidence without record bodies",
            ),
            self._manual_evidence_check(
                "artifact_manifest_not_writable",
                (
                    "passed"
                    if artifact_manifest.get("artifact_write_allowed") is False
                    and artifact_manifest.get("artifact_path") is None
                    else "blocked"
                ),
                {
                    "artifact_write_allowed": artifact_manifest.get("artifact_write_allowed"),
                    "artifact_path": artifact_manifest.get("artifact_path"),
                },
                "artifact_write_allowed=false and artifact_path=null",
                "P75 must confirm the P74 artifact manifest is review-only metadata",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "would_write_model_artifact": simulation_result.get("would_write_model_artifact"),
                    "would_write_file": simulation_result.get("would_write_file"),
                    "would_execute_training": simulation_result.get("would_execute_training"),
                    "training_started_now": simulation_result.get("training_started_now"),
                    "decision_model_artifact_written": dry_decision.get("model_artifact_written"),
                    "decision_writes_file": dry_decision.get("writes_file"),
                    "decision_can_execute_training_now": dry_decision.get("can_execute_dataset2_training_now"),
                },
                "all false",
                "P75 must confirm P74 did not write files, write model artifacts, or execute training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training release dry-run review cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_release_dry_run_review.v1",
            "stage": "V5.6-P75",
            "status": (
                "dataset2_controlled_training_execution_release_dry_run_review_accepted"
                if accepted
                else "dataset2_controlled_training_execution_release_dry_run_review_blocked"
            ),
            "generated_at": now,
            "package_id": (release_dry_run or {}).get("package_id"),
            "review": {
                "reviewed_by": reviewed_by or "operator",
                "review_decision": review_decision,
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "release_dry_run_event_id": (release_dry_run or {}).get("id"),
                "release_preflight_event_id": dry_evidence.get("release_preflight_event_id"),
                "release_plan_event_id": dry_evidence.get("release_plan_event_id"),
                "release_plan_id": dry_evidence.get("release_plan_id"),
                "release_plan_hash": dry_evidence.get("release_plan_hash"),
                "dry_run_review_id": dry_evidence.get("dry_run_review_id"),
                "dry_run_event_id": dry_evidence.get("dry_run_event_id"),
                "manifest_hash": dry_evidence.get("manifest_hash"),
                "release_simulation_manifest_hash": simulation_result.get("release_simulation_manifest_hash"),
                "artifact_manifest_hash": simulation_result.get("artifact_manifest_hash"),
                "sample_set_hash": sample_set_hash,
                "learning_sample_count": sample_count,
                "source_type": "dataset2_staging",
            },
            "manifest_review": {
                "manifest_kind": release_manifest.get("manifest_kind"),
                "model_family": simulation_result.get("model_family") or release_manifest.get("model_family"),
                "validation_policy": simulation_result.get("validation_policy")
                or release_manifest.get("validation_policy"),
                "baseline_accuracy": simulation_result.get("baseline_accuracy")
                or release_manifest.get("baseline_accuracy"),
                "label_counts": label_counts,
                "split_counts": split_counts,
                "risk_level_counts": risk_counts,
                "feature_key_count": simulation_result.get("feature_key_count"),
                "artifact_write_allowed": artifact_manifest.get("artifact_write_allowed"),
                "artifact_path": artifact_manifest.get("artifact_path"),
                "would_write_model_artifact": False,
                "would_write_file": False,
                "would_execute_training": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_final_approval"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_release_dry_run_review_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_release_dry_run_review_recorded": True,
                "controlled_dataset2_training_execution_release_dry_run_review_accepted": accepted,
                "can_prepare_controlled_dataset2_training_execution_final_approval_now": accepted,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_final_approval"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_release_dry_run_review_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_release_dry_run_review_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

