    def dataset2_controlled_training_execution_final_dry_run(
        self,
        final_preflight_event_id: int | None = None,
        simulated_by: str = "operator",
        confirmation_token: str | None = None,
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Simulate the final controlled Dataset2 training execution without writing artifacts."""
        store = SQLiteStore(settings.database_path)
        store.init()
        preflight = self._dataset2_controlled_training_execution_final_preflight_by_id(
            store,
            final_preflight_event_id,
        )
        preflight_decision = (preflight or {}).get("decision") or {}
        preflight_evidence = (preflight or {}).get("evidence") or {}
        final_preflight = (preflight or {}).get("final_preflight") or {}
        resolved_package_id = (preflight or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("source_id") or row.get("id") or "") for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids)
        label_counts: Counter[str] = Counter()
        split_counts: Counter[str] = Counter()
        risk_counts: Counter[str] = Counter()
        feature_key_counts: Counter[str] = Counter()
        for row in rows:
            features = json.loads(row.get("features_json") or "{}")
            label_counts[str(row.get("label") or "unknown")] += 1
            split_counts[str(features.get("split_tag") or "unknown")] += 1
            risk_counts[str(row.get("risk_level") or "unknown")] += 1
            for key in features.keys():
                feature_key_counts[str(key)] += 1

        expected_token = final_preflight.get("expected_confirmation_token") or "RUN_DATASET2_CONTROLLED_TRAINING_FINAL_DRY_RUN"
        preflight_ready = (
            preflight
            and preflight.get("status") == "dataset2_controlled_training_execution_final_preflight_ready"
            and preflight_decision.get("controlled_dataset2_training_execution_final_preflight_ready") is True
            and preflight_decision.get("can_prepare_controlled_dataset2_training_execution_final_dry_run_now") is True
        )
        artifact_write_still_disabled = (
            final_preflight.get("artifact_write_allowed") is False
            and final_preflight.get("artifact_path") is None
            and final_preflight.get("writes_model_artifact_now") is False
            and final_preflight.get("writes_file_now") is False
            and final_preflight.get("executes_training_now") is False
            and final_preflight.get("training_started_now") is False
        )
        no_training_started_or_file_written = (
            preflight_decision.get("model_artifact_written") is False
            and preflight_decision.get("writes_file") is False
            and preflight_decision.get("training_started_now") is False
            and preflight_decision.get("can_execute_dataset2_training_now") is False
            and preflight_decision.get("can_start_training_now") is False
        )
        simulated_artifact_manifest = {
            "artifact_kind": "dataset2_controlled_training_final_model_artifact_manifest",
            "artifact_write_allowed": False,
            "artifact_path": None,
            "approved_artifact_manifest_hash": preflight_evidence.get("artifact_manifest_hash"),
            "release_simulation_manifest_hash": preflight_evidence.get("release_simulation_manifest_hash"),
            "model_family": final_preflight.get("model_family"),
            "validation_policy": final_preflight.get("validation_policy"),
            "sample_set_hash": current_sample_set_hash,
            "learning_sample_count": len(rows),
            "label_counts": dict(label_counts),
            "split_counts": dict(split_counts),
            "risk_level_counts": dict(risk_counts),
            "feature_key_count": len(feature_key_counts),
        }
        simulated_artifact_manifest_hash = self._stable_hash(simulated_artifact_manifest)
        final_dry_run_manifest = {
            "manifest_kind": "dataset2_controlled_training_final_dry_run_manifest",
            "final_preflight_event_id": (preflight or {}).get("id"),
            "final_approval_id": preflight_evidence.get("final_approval_id"),
            "release_dry_run_review_id": preflight_evidence.get("release_dry_run_review_id"),
            "release_dry_run_event_id": preflight_evidence.get("release_dry_run_event_id"),
            "release_plan_id": preflight_evidence.get("release_plan_id"),
            "release_plan_hash": preflight_evidence.get("release_plan_hash"),
            "manifest_hash": preflight_evidence.get("manifest_hash"),
            "release_simulation_manifest_hash": preflight_evidence.get("release_simulation_manifest_hash"),
            "approved_artifact_manifest_hash": preflight_evidence.get("artifact_manifest_hash"),
            "simulated_artifact_manifest_hash": simulated_artifact_manifest_hash,
            "sample_set_hash": current_sample_set_hash,
            "learning_sample_count": len(rows),
            "model_family": final_preflight.get("model_family"),
            "validation_policy": final_preflight.get("validation_policy"),
            "baseline_accuracy": final_preflight.get("baseline_accuracy"),
            "would_write_model_artifact": False,
            "would_write_file": False,
            "would_execute_training": False,
            "training_started_now": False,
            "record_bodies_included": False,
        }
        final_dry_run_manifest_hash = self._stable_hash(final_dry_run_manifest)
        checks = [
            self._manual_evidence_check(
                "final_preflight_ready",
                "passed" if preflight_ready else "blocked",
                {
                    "final_preflight_event_id": (preflight or {}).get("id"),
                    "final_preflight_status": (preflight or {}).get("status"),
                    "can_prepare_final_dry_run": preflight_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_final_dry_run_now"
                    ),
                },
                "ready P77 final preflight",
                "P78 can only simulate final training execution after a ready P77 preflight",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P78 requires explicit operator confirmation before final dry-run metadata is recorded",
            ),
            self._manual_evidence_check(
                "release_simulation_manifest_hash_pinned",
                "passed" if bool(preflight_evidence.get("release_simulation_manifest_hash")) else "blocked",
                preflight_evidence.get("release_simulation_manifest_hash"),
                "non-empty release_simulation_manifest_hash",
                "P78 must preserve P77-approved release simulation manifest traceability",
            ),
            self._manual_evidence_check(
                "artifact_manifest_hash_pinned",
                "passed" if bool(preflight_evidence.get("artifact_manifest_hash")) else "blocked",
                preflight_evidence.get("artifact_manifest_hash"),
                "non-empty artifact_manifest_hash",
                "P78 must preserve P77-approved no-write artifact manifest traceability",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_preflight",
                (
                    "passed"
                    if rows and current_sample_set_hash == preflight_evidence.get("current_sample_set_hash")
                    else "blocked"
                ),
                {
                    "current_sample_set_hash": current_sample_set_hash,
                    "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                },
                "matching sample_set_hash",
                "P78 dry-run must simulate the same Dataset2 sample set as P77",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_preflight",
                (
                    "passed"
                    if rows and len(rows) == preflight_evidence.get("current_learning_sample_count")
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                },
                "current count equals P77 count",
                "P78 dry-run must verify Dataset2 sample count has not drifted",
            ),
            self._manual_evidence_check(
                "artifact_write_still_disabled",
                "passed" if artifact_write_still_disabled else "blocked",
                {
                    "artifact_write_allowed": final_preflight.get("artifact_write_allowed"),
                    "artifact_path": final_preflight.get("artifact_path"),
                    "writes_model_artifact_now": final_preflight.get("writes_model_artifact_now"),
                    "writes_file_now": final_preflight.get("writes_file_now"),
                    "executes_training_now": final_preflight.get("executes_training_now"),
                    "training_started_now": final_preflight.get("training_started_now"),
                },
                "all artifact and execution flags disabled",
                "P78 final dry-run must not enable model artifact or file writing",
            ),
            self._manual_evidence_check(
                "simulated_final_dry_run_manifest_hash_recorded",
                "passed" if bool(final_dry_run_manifest_hash) else "blocked",
                final_dry_run_manifest_hash,
                "non-empty final_dry_run_manifest_hash",
                "P78 must produce deterministic final dry-run metadata without writing artifacts",
            ),
            self._manual_evidence_check(
                "no_training_started_or_file_written",
                "passed" if no_training_started_or_file_written else "blocked",
                {
                    "model_artifact_written": preflight_decision.get("model_artifact_written"),
                    "writes_file": preflight_decision.get("writes_file"),
                    "training_started_now": preflight_decision.get("training_started_now"),
                    "can_execute_dataset2_training_now": preflight_decision.get("can_execute_dataset2_training_now"),
                    "can_start_training_now": preflight_decision.get("can_start_training_now"),
                },
                "all false",
                "P78 records final dry-run evidence only and cannot start training or write files",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training final dry-run cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        completed = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_final_dry_run.v1",
            "stage": "V5.6-P78",
            "status": (
                "dataset2_controlled_training_execution_final_dry_run_completed"
                if completed
                else "dataset2_controlled_training_execution_final_dry_run_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "dry_run": {
                "simulated_by": simulated_by or "operator",
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "record_bodies_included": False,
                "model_artifact_written": False,
                "writes_file": False,
                "executes_training_now": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "final_preflight_event_id": (preflight or {}).get("id"),
                "final_approval_id": preflight_evidence.get("final_approval_id"),
                "release_dry_run_review_id": preflight_evidence.get("release_dry_run_review_id"),
                "release_dry_run_event_id": preflight_evidence.get("release_dry_run_event_id"),
                "release_preflight_event_id": preflight_evidence.get("release_preflight_event_id"),
                "release_plan_event_id": preflight_evidence.get("release_plan_event_id"),
                "release_plan_id": preflight_evidence.get("release_plan_id"),
                "release_plan_hash": preflight_evidence.get("release_plan_hash"),
                "dry_run_review_id": preflight_evidence.get("dry_run_review_id"),
                "dry_run_event_id": preflight_evidence.get("dry_run_event_id"),
                "manifest_hash": preflight_evidence.get("manifest_hash"),
                "release_simulation_manifest_hash": preflight_evidence.get("release_simulation_manifest_hash"),
                "approved_artifact_manifest_hash": preflight_evidence.get("artifact_manifest_hash"),
                "simulated_artifact_manifest_hash": simulated_artifact_manifest_hash,
                "final_dry_run_manifest_hash": final_dry_run_manifest_hash,
                "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                "current_sample_set_hash": current_sample_set_hash,
                "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                "current_learning_sample_count": len(rows),
                "source_type": "dataset2_staging",
            },
            "simulation_result": {
                "final_dry_run_manifest": final_dry_run_manifest,
                "final_dry_run_manifest_hash": final_dry_run_manifest_hash,
                "artifact_manifest": simulated_artifact_manifest,
                "artifact_manifest_hash": simulated_artifact_manifest_hash,
                "approved_artifact_manifest_hash": preflight_evidence.get("artifact_manifest_hash"),
                "label_counts": dict(label_counts),
                "split_counts": dict(split_counts),
                "risk_level_counts": dict(risk_counts),
                "feature_key_count": len(feature_key_counts),
                "baseline_accuracy": final_preflight.get("baseline_accuracy"),
                "model_family": final_preflight.get("model_family"),
                "validation_policy": final_preflight.get("validation_policy"),
                "would_write_model_artifact": False,
                "would_write_file": False,
                "would_execute_training": False,
                "training_started_now": False,
                "record_bodies_included": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_final_dry_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_final_dry_run_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_final_dry_run_recorded": True,
                "controlled_dataset2_training_execution_final_dry_run_completed": completed,
                "can_prepare_controlled_dataset2_training_execution_final_dry_run_review_now": completed,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_final_dry_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_final_dry_run_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_final_dry_run_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

    def list_dataset2_controlled_training_execution_final_dry_runs(
        self,
        limit: int = 20,
    ) -> list[dict[str, Any]]:
        store = SQLiteStore(settings.database_path)
        store.init()
        rows = store.fetch_all(
            """
            SELECT id, event_type, payload_json, created_at
            FROM events
            WHERE event_type = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (
                self.dataset2_controlled_training_execution_final_dry_run_event_type,
                max(1, min(limit, 100)),
            ),
        )
        return [self._event_payload(row) for row in rows]

    def dataset2_controlled_training_execution_final_dry_run_review(
        self,
        final_dry_run_event_id: int | None = None,
        reviewed_by: str = "operator",
        review_decision: str = "accepted_for_controlled_dataset2_training_execution_run_approval",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Review the final controlled Dataset2 training dry-run before any execution approval."""
        store = SQLiteStore(settings.database_path)
        store.init()
        dry_run = self._dataset2_controlled_training_execution_final_dry_run_by_id(
            store,
            final_dry_run_event_id,
        )
        dry_decision = (dry_run or {}).get("decision") or {}
        dry_evidence = (dry_run or {}).get("evidence") or {}
        simulation_result = (dry_run or {}).get("simulation_result") or {}
        final_manifest = simulation_result.get("final_dry_run_manifest") or {}
        artifact_manifest = simulation_result.get("artifact_manifest") or {}
        allowed_decision = "accepted_for_controlled_dataset2_training_execution_run_approval"
        final_dry_run_completed = (
            dry_run
            and dry_run.get("status") == "dataset2_controlled_training_execution_final_dry_run_completed"
            and dry_decision.get("controlled_dataset2_training_execution_final_dry_run_completed") is True
            and dry_decision.get("can_prepare_controlled_dataset2_training_execution_final_dry_run_review_now")
            is True
        )
        no_execution_or_artifact = (
            simulation_result.get("would_write_model_artifact") is False
            and simulation_result.get("would_write_file") is False
            and simulation_result.get("would_execute_training") is False
            and simulation_result.get("training_started_now") is False
            and artifact_manifest.get("artifact_write_allowed") is False
            and artifact_manifest.get("artifact_path") is None
            and dry_decision.get("model_artifact_written") is False
            and dry_decision.get("writes_file") is False
            and dry_decision.get("training_started_now") is False
            and dry_decision.get("can_execute_dataset2_training_now") is False
        )
        sample_count = int(dry_evidence.get("current_learning_sample_count") or 0)
        label_counts = simulation_result.get("label_counts") or {}
        split_counts = simulation_result.get("split_counts") or {}
        risk_counts = simulation_result.get("risk_level_counts") or {}
        sample_set_hash = dry_evidence.get("current_sample_set_hash") or final_manifest.get("sample_set_hash")
        checks = [
            self._manual_evidence_check(
                "final_dry_run_completed",
                "passed" if final_dry_run_completed else "blocked",
                {
                    "final_dry_run_event_id": (dry_run or {}).get("id"),
                    "final_dry_run_status": (dry_run or {}).get("status"),
                    "can_prepare_review": dry_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_final_dry_run_review_now"
                    ),
                },
                "completed P78 final dry-run",
                "P79 can only review completed P78 final dry-run evidence",
            ),
            self._manual_evidence_check(
                "review_decision_allowed",
                "passed" if review_decision == allowed_decision else "blocked",
                review_decision,
                allowed_decision,
                "P79 review can only accept evidence for a later controlled training execution approval gate",
            ),
            self._manual_evidence_check(
                "final_dry_run_manifest_hash_recorded",
                "passed" if bool(simulation_result.get("final_dry_run_manifest_hash")) else "blocked",
                simulation_result.get("final_dry_run_manifest_hash"),
                "non-empty final_dry_run_manifest_hash",
                "P79 must pin review evidence to the P78 final dry-run manifest",
            ),
            self._manual_evidence_check(
                "artifact_manifest_hash_recorded",
                "passed" if bool(simulation_result.get("artifact_manifest_hash")) else "blocked",
                simulation_result.get("artifact_manifest_hash"),
                "non-empty artifact_manifest_hash",
                "P79 must preserve the simulated model artifact manifest hash without writing it",
            ),
            self._manual_evidence_check(
                "release_simulation_manifest_hash_recorded",
                "passed" if bool(dry_evidence.get("release_simulation_manifest_hash")) else "blocked",
                dry_evidence.get("release_simulation_manifest_hash"),
                "non-empty release_simulation_manifest_hash",
                "P79 must preserve the previously reviewed release simulation manifest hash",
            ),
            self._manual_evidence_check(
                "sample_set_hash_recorded",
                "passed" if bool(sample_set_hash) else "blocked",
                {
                    "evidence_sample_set_hash": dry_evidence.get("current_sample_set_hash"),
                    "final_manifest_sample_set_hash": final_manifest.get("sample_set_hash"),
                },
                "non-empty sample_set_hash",
                "P79 must preserve Dataset2 sample-set traceability before execution approval",
            ),
            self._manual_evidence_check(
                "learning_sample_distribution_present",
                "passed" if sample_count > 0 and bool(label_counts) and bool(split_counts) else "blocked",
                {
                    "learning_sample_count": sample_count,
                    "label_counts": label_counts,
                    "split_counts": split_counts,
                    "risk_level_counts": risk_counts,
                },
                "samples with label and split distributions",
                "P79 review needs aggregate distribution evidence without record bodies",
            ),
            self._manual_evidence_check(
                "artifact_manifest_not_writable",
                (
                    "passed"
                    if artifact_manifest.get("artifact_write_allowed") is False
                    and artifact_manifest.get("artifact_path") is None
                    else "blocked"
                ),
                {
                    "artifact_write_allowed": artifact_manifest.get("artifact_write_allowed"),
                    "artifact_path": artifact_manifest.get("artifact_path"),
                },
                "artifact_write_allowed=false and artifact_path=null",
                "P79 must confirm the P78 artifact manifest is review-only metadata",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "would_write_model_artifact": simulation_result.get("would_write_model_artifact"),
                    "would_write_file": simulation_result.get("would_write_file"),
                    "would_execute_training": simulation_result.get("would_execute_training"),
                    "training_started_now": simulation_result.get("training_started_now"),
                    "decision_model_artifact_written": dry_decision.get("model_artifact_written"),
                    "decision_writes_file": dry_decision.get("writes_file"),
                    "decision_can_execute_training_now": dry_decision.get("can_execute_dataset2_training_now"),
                },
                "all false",
                "P79 must confirm P78 did not write files, write model artifacts, or execute training",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training final dry-run review cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_final_dry_run_review.v1",
            "stage": "V5.6-P79",
            "status": (
                "dataset2_controlled_training_execution_final_dry_run_review_accepted"
                if accepted
                else "dataset2_controlled_training_execution_final_dry_run_review_blocked"
            ),
            "generated_at": now,
            "package_id": (dry_run or {}).get("package_id"),
            "review": {
                "reviewed_by": reviewed_by or "operator",
                "review_decision": review_decision,
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "final_dry_run_event_id": (dry_run or {}).get("id"),
                "final_preflight_event_id": dry_evidence.get("final_preflight_event_id"),
                "final_approval_id": dry_evidence.get("final_approval_id"),
                "release_dry_run_review_id": dry_evidence.get("release_dry_run_review_id"),
                "release_dry_run_event_id": dry_evidence.get("release_dry_run_event_id"),
                "release_preflight_event_id": dry_evidence.get("release_preflight_event_id"),
                "release_plan_event_id": dry_evidence.get("release_plan_event_id"),
                "release_plan_id": dry_evidence.get("release_plan_id"),
                "release_plan_hash": dry_evidence.get("release_plan_hash"),
                "dry_run_review_id": dry_evidence.get("dry_run_review_id"),
                "dry_run_event_id": dry_evidence.get("dry_run_event_id"),
                "manifest_hash": dry_evidence.get("manifest_hash"),
                "release_simulation_manifest_hash": dry_evidence.get("release_simulation_manifest_hash"),
                "approved_artifact_manifest_hash": dry_evidence.get("approved_artifact_manifest_hash"),
                "simulated_artifact_manifest_hash": simulation_result.get("artifact_manifest_hash"),
                "final_dry_run_manifest_hash": simulation_result.get("final_dry_run_manifest_hash"),
                "sample_set_hash": sample_set_hash,
                "learning_sample_count": sample_count,
                "source_type": "dataset2_staging",
            },
            "manifest_review": {
                "manifest_kind": final_manifest.get("manifest_kind"),
                "model_family": simulation_result.get("model_family") or final_manifest.get("model_family"),
                "validation_policy": simulation_result.get("validation_policy") or final_manifest.get("validation_policy"),
                "baseline_accuracy": simulation_result.get("baseline_accuracy") or final_manifest.get("baseline_accuracy"),
                "label_counts": label_counts,
                "split_counts": split_counts,
                "risk_level_counts": risk_counts,
                "feature_key_count": simulation_result.get("feature_key_count"),
                "artifact_write_allowed": artifact_manifest.get("artifact_write_allowed"),
                "artifact_path": artifact_manifest.get("artifact_path"),
                "would_write_model_artifact": False,
                "would_write_file": False,
                "would_execute_training": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_run_approval"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_final_dry_run_review_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_final_dry_run_review_recorded": True,
                "controlled_dataset2_training_execution_final_dry_run_review_accepted": accepted,
                "can_prepare_controlled_dataset2_training_execution_run_approval_now": accepted,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_run_approval"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_final_dry_run_review_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_final_dry_run_review_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

