    def dataset2_controlled_training_execution_run_approval(
        self,
        final_dry_run_review_id: int | None = None,
        approved_by: str = "operator",
        approval_decision: str = "approved_for_controlled_dataset2_training_execution_run_preflight",
        confirmation_token: str | None = None,
        note: str | None = None,
    ) -> dict[str, Any]:
        """Record approval metadata before any controlled Dataset2 training run preflight."""
        store = SQLiteStore(settings.database_path)
        store.init()
        review = self._dataset2_controlled_training_execution_final_dry_run_review_by_id(
            store,
            final_dry_run_review_id,
        )
        review_decision_payload = (review or {}).get("decision") or {}
        review_evidence = (review or {}).get("evidence") or {}
        manifest_review = (review or {}).get("manifest_review") or {}
        expected_token = "APPROVE_DATASET2_CONTROLLED_TRAINING_EXECUTION_RUN"
        expected_decision = "approved_for_controlled_dataset2_training_execution_run_preflight"
        review_accepted = (
            review
            and review.get("status") == "dataset2_controlled_training_execution_final_dry_run_review_accepted"
            and review_decision_payload.get("controlled_dataset2_training_execution_final_dry_run_review_accepted")
            is True
            and review_decision_payload.get("can_prepare_controlled_dataset2_training_execution_run_approval_now")
            is True
        )
        no_execution_or_artifact = (
            manifest_review.get("would_write_model_artifact") is False
            and manifest_review.get("would_write_file") is False
            and manifest_review.get("would_execute_training") is False
            and manifest_review.get("training_started_now") is False
            and manifest_review.get("artifact_write_allowed") is False
            and manifest_review.get("artifact_path") is None
            and review_decision_payload.get("model_artifact_written") is False
            and review_decision_payload.get("writes_file") is False
            and review_decision_payload.get("training_started_now") is False
            and review_decision_payload.get("can_execute_dataset2_training_now") is False
        )
        checks = [
            self._manual_evidence_check(
                "final_dry_run_review_accepted",
                "passed" if review_accepted else "blocked",
                {
                    "final_dry_run_review_id": (review or {}).get("id"),
                    "final_dry_run_review_status": (review or {}).get("status"),
                    "can_prepare_run_approval": review_decision_payload.get(
                        "can_prepare_controlled_dataset2_training_execution_run_approval_now"
                    ),
                },
                "accepted P79 final dry-run review",
                "P80 can only record run approval metadata after accepted P79 review evidence",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P80 requires explicit operator confirmation before run approval metadata is recorded",
            ),
            self._manual_evidence_check(
                "approval_decision_allowed",
                "passed" if approval_decision == expected_decision else "blocked",
                approval_decision,
                expected_decision,
                "P80 approval can only target a later controlled training run preflight, not immediate training",
            ),
            self._manual_evidence_check(
                "final_dry_run_manifest_hash_pinned",
                "passed" if bool(review_evidence.get("final_dry_run_manifest_hash")) else "blocked",
                review_evidence.get("final_dry_run_manifest_hash"),
                "non-empty final_dry_run_manifest_hash",
                "P80 must pin to the reviewed P78 final dry-run manifest hash",
            ),
            self._manual_evidence_check(
                "artifact_manifest_hash_pinned",
                "passed" if bool(review_evidence.get("simulated_artifact_manifest_hash")) else "blocked",
                review_evidence.get("simulated_artifact_manifest_hash"),
                "non-empty simulated_artifact_manifest_hash",
                "P80 must pin to the reviewed no-write artifact manifest hash",
            ),
            self._manual_evidence_check(
                "release_simulation_manifest_hash_pinned",
                "passed" if bool(review_evidence.get("release_simulation_manifest_hash")) else "blocked",
                review_evidence.get("release_simulation_manifest_hash"),
                "non-empty release_simulation_manifest_hash",
                "P80 must preserve release simulation traceability before run preflight",
            ),
            self._manual_evidence_check(
                "sample_set_hash_pinned",
                "passed" if bool(review_evidence.get("sample_set_hash")) else "blocked",
                review_evidence.get("sample_set_hash"),
                "non-empty sample_set_hash",
                "P80 must preserve Dataset2 sample-set traceability before run preflight",
            ),
            self._manual_evidence_check(
                "learning_sample_distribution_present",
                (
                    "passed"
                    if int(review_evidence.get("learning_sample_count") or 0) > 0
                    and bool(manifest_review.get("label_counts"))
                    and bool(manifest_review.get("split_counts"))
                    else "blocked"
                ),
                {
                    "learning_sample_count": review_evidence.get("learning_sample_count"),
                    "label_counts": manifest_review.get("label_counts"),
                    "split_counts": manifest_review.get("split_counts"),
                    "risk_level_counts": manifest_review.get("risk_level_counts"),
                },
                "samples with label and split distributions",
                "P80 approval metadata needs aggregate distribution evidence without record bodies",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "would_write_model_artifact": manifest_review.get("would_write_model_artifact"),
                    "would_write_file": manifest_review.get("would_write_file"),
                    "would_execute_training": manifest_review.get("would_execute_training"),
                    "training_started_now": manifest_review.get("training_started_now"),
                    "artifact_write_allowed": manifest_review.get("artifact_write_allowed"),
                    "artifact_path": manifest_review.get("artifact_path"),
                    "decision_model_artifact_written": review_decision_payload.get("model_artifact_written"),
                    "decision_writes_file": review_decision_payload.get("writes_file"),
                    "decision_can_execute_training_now": review_decision_payload.get("can_execute_dataset2_training_now"),
                },
                "all false",
                "P80 must confirm run approval metadata does not execute training or write artifacts",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training run approval metadata cannot be recorded while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_run_approval.v1",
            "stage": "V5.6-P80",
            "status": (
                "dataset2_controlled_training_execution_run_approval_accepted"
                if accepted
                else "dataset2_controlled_training_execution_run_approval_blocked"
            ),
            "generated_at": now,
            "package_id": (review or {}).get("package_id"),
            "approval": {
                "approved_by": approved_by or "operator",
                "approval_decision": approval_decision,
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "approved_for_controlled_dataset2_training_execution_run_preflight": accepted,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "final_dry_run_review_id": (review or {}).get("id"),
                "final_dry_run_event_id": review_evidence.get("final_dry_run_event_id"),
                "final_preflight_event_id": review_evidence.get("final_preflight_event_id"),
                "final_approval_id": review_evidence.get("final_approval_id"),
                "release_dry_run_review_id": review_evidence.get("release_dry_run_review_id"),
                "release_dry_run_event_id": review_evidence.get("release_dry_run_event_id"),
                "release_preflight_event_id": review_evidence.get("release_preflight_event_id"),
                "release_plan_event_id": review_evidence.get("release_plan_event_id"),
                "release_plan_id": review_evidence.get("release_plan_id"),
                "release_plan_hash": review_evidence.get("release_plan_hash"),
                "dry_run_review_id": review_evidence.get("dry_run_review_id"),
                "dry_run_event_id": review_evidence.get("dry_run_event_id"),
                "manifest_hash": review_evidence.get("manifest_hash"),
                "release_simulation_manifest_hash": review_evidence.get("release_simulation_manifest_hash"),
                "approved_artifact_manifest_hash": review_evidence.get("approved_artifact_manifest_hash"),
                "simulated_artifact_manifest_hash": review_evidence.get("simulated_artifact_manifest_hash"),
                "final_dry_run_manifest_hash": review_evidence.get("final_dry_run_manifest_hash"),
                "sample_set_hash": review_evidence.get("sample_set_hash"),
                "learning_sample_count": review_evidence.get("learning_sample_count"),
                "source_type": "dataset2_staging",
            },
            "approval_scope": {
                "allowed_next_stage": "controlled_dataset2_training_execution_run_preflight",
                "expected_confirmation_token": "PREPARE_DATASET2_CONTROLLED_TRAINING_EXECUTION_RUN_PREFLIGHT",
                "model_family": manifest_review.get("model_family"),
                "validation_policy": manifest_review.get("validation_policy"),
                "baseline_accuracy": manifest_review.get("baseline_accuracy"),
                "feature_key_count": manifest_review.get("feature_key_count"),
                "artifact_write_allowed": False,
                "artifact_path": None,
                "writes_model_artifact_now": False,
                "writes_file_now": False,
                "executes_training_now": False,
                "training_started_now": False,
                "record_bodies_included": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_run_preflight"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_run_approval_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_run_approval_recorded": True,
                "controlled_dataset2_training_execution_run_approval_accepted": accepted,
                "can_prepare_controlled_dataset2_training_execution_run_preflight_now": accepted,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_execution_run_preflight"
                    if accepted
                    else "resolve_controlled_dataset2_training_execution_run_approval_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_run_approval_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

