    def dataset2_controlled_training_execution_run_preflight(
        self,
        run_approval_id: int | None = None,
        requested_by: str = "operator",
        confirmation_token: str | None = None,
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Preflight an accepted P80 approval before any controlled Dataset2 training run."""
        store = SQLiteStore(settings.database_path)
        store.init()
        approval = self._dataset2_controlled_training_execution_run_approval_by_id(
            store,
            run_approval_id,
        )
        approval_decision = (approval or {}).get("decision") or {}
        approval_evidence = (approval or {}).get("evidence") or {}
        approval_scope = (approval or {}).get("approval_scope") or {}
        resolved_package_id = (approval or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("sample_id") or row.get("source_id") or row.get("id")) for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids) if sample_ids else None
        label_counts = Counter(str(row.get("label") or "unknown") for row in rows)
        split_counts = Counter(str(row.get("split_tag") or "unknown") for row in rows)
        risk_counts = Counter(str(row.get("risk_level") or "unknown") for row in rows)
        expected_token = "PREPARE_DATASET2_CONTROLLED_TRAINING_EXECUTION_RUN_PREFLIGHT"
        approval_accepted = (
            approval
            and approval.get("status") == "dataset2_controlled_training_execution_run_approval_accepted"
            and approval_decision.get("controlled_dataset2_training_execution_run_approval_accepted") is True
            and approval_decision.get("can_prepare_controlled_dataset2_training_execution_run_preflight_now") is True
        )
        no_execution_or_artifact = (
            approval_scope.get("writes_model_artifact_now") is False
            and approval_scope.get("writes_file_now") is False
            and approval_scope.get("executes_training_now") is False
            and approval_scope.get("training_started_now") is False
            and approval_scope.get("artifact_write_allowed") is False
            and approval_scope.get("artifact_path") is None
            and approval_decision.get("model_artifact_written") is False
            and approval_decision.get("writes_file") is False
            and approval_decision.get("training_started_now") is False
            and approval_decision.get("can_execute_dataset2_training_now") is False
            and approval_decision.get("can_start_training_now") is False
        )
        checks = [
            self._manual_evidence_check(
                "run_approval_accepted",
                "passed" if approval_accepted else "blocked",
                {
                    "run_approval_id": (approval or {}).get("id"),
                    "run_approval_status": (approval or {}).get("status"),
                    "can_prepare_run_preflight": approval_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_run_preflight_now"
                    ),
                },
                "accepted P80 run approval",
                "P81 can only preflight after accepted P80 approval metadata",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P81 requires explicit operator confirmation before run preflight metadata is recorded",
            ),
            self._manual_evidence_check(
                "approval_scope_targets_run_preflight",
                (
                    "passed"
                    if approval_scope.get("allowed_next_stage")
                    == "controlled_dataset2_training_execution_run_preflight"
                    else "blocked"
                ),
                approval_scope.get("allowed_next_stage"),
                "controlled_dataset2_training_execution_run_preflight",
                "P80 approval scope must target only a later run preflight",
            ),
            self._manual_evidence_check(
                "dataset2_learning_samples_still_available",
                "passed" if rows else "blocked",
                {
                    "approved_learning_sample_count": approval_evidence.get("learning_sample_count"),
                    "current_learning_sample_count": len(rows),
                },
                ">0 and consistent with P80 approval",
                "P81 must verify Dataset2 learning samples are still available before run preflight",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_approval",
                (
                    "passed"
                    if int(approval_evidence.get("learning_sample_count") or 0) == len(rows)
                    and len(rows) > 0
                    else "blocked"
                ),
                {
                    "approved_learning_sample_count": approval_evidence.get("learning_sample_count"),
                    "current_learning_sample_count": len(rows),
                },
                "matching sample counts",
                "P81 must block if Dataset2 learning sample count drifted after P80 approval",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_approval",
                (
                    "passed"
                    if bool(current_sample_set_hash)
                    and current_sample_set_hash == approval_evidence.get("sample_set_hash")
                    else "blocked"
                ),
                {
                    "approved_sample_set_hash": approval_evidence.get("sample_set_hash"),
                    "current_sample_set_hash": current_sample_set_hash,
                },
                "matching sample-set hash",
                "P81 must block if Dataset2 sample-set hash drifted after P80 approval",
            ),
            self._manual_evidence_check(
                "final_dry_run_and_artifact_hashes_pinned",
                (
                    "passed"
                    if bool(approval_evidence.get("final_dry_run_manifest_hash"))
                    and bool(approval_evidence.get("simulated_artifact_manifest_hash"))
                    and bool(approval_evidence.get("release_simulation_manifest_hash"))
                    else "blocked"
                ),
                {
                    "final_dry_run_manifest_hash": approval_evidence.get("final_dry_run_manifest_hash"),
                    "simulated_artifact_manifest_hash": approval_evidence.get("simulated_artifact_manifest_hash"),
                    "release_simulation_manifest_hash": approval_evidence.get("release_simulation_manifest_hash"),
                },
                "all hashes pinned",
                "P81 must preserve final dry-run, artifact, and release simulation traceability",
            ),
            self._manual_evidence_check(
                "no_model_artifact_file_or_training_started",
                "passed" if no_execution_or_artifact else "blocked",
                {
                    "writes_model_artifact_now": approval_scope.get("writes_model_artifact_now"),
                    "writes_file_now": approval_scope.get("writes_file_now"),
                    "executes_training_now": approval_scope.get("executes_training_now"),
                    "training_started_now": approval_scope.get("training_started_now"),
                    "artifact_write_allowed": approval_scope.get("artifact_write_allowed"),
                    "artifact_path": approval_scope.get("artifact_path"),
                    "decision_model_artifact_written": approval_decision.get("model_artifact_written"),
                    "decision_writes_file": approval_decision.get("writes_file"),
                    "decision_can_execute_training_now": approval_decision.get("can_execute_dataset2_training_now"),
                },
                "all false",
                "P81 must not execute training or write artifacts/files",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training run preflight cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        ready = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_run_preflight.v1",
            "stage": "V5.6-P81",
            "status": (
                "dataset2_controlled_training_execution_run_preflight_ready"
                if ready
                else "dataset2_controlled_training_execution_run_preflight_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "preflight": {
                "requested_by": requested_by or "operator",
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "run_approval_id": (approval or {}).get("id"),
                "final_dry_run_review_id": approval_evidence.get("final_dry_run_review_id"),
                "final_dry_run_event_id": approval_evidence.get("final_dry_run_event_id"),
                "final_preflight_event_id": approval_evidence.get("final_preflight_event_id"),
                "final_approval_id": approval_evidence.get("final_approval_id"),
                "release_dry_run_review_id": approval_evidence.get("release_dry_run_review_id"),
                "release_dry_run_event_id": approval_evidence.get("release_dry_run_event_id"),
                "release_plan_id": approval_evidence.get("release_plan_id"),
                "release_plan_hash": approval_evidence.get("release_plan_hash"),
                "final_dry_run_manifest_hash": approval_evidence.get("final_dry_run_manifest_hash"),
                "simulated_artifact_manifest_hash": approval_evidence.get("simulated_artifact_manifest_hash"),
                "release_simulation_manifest_hash": approval_evidence.get("release_simulation_manifest_hash"),
                "approved_sample_set_hash": approval_evidence.get("sample_set_hash"),
                "current_sample_set_hash": current_sample_set_hash,
                "approved_learning_sample_count": approval_evidence.get("learning_sample_count"),
                "current_learning_sample_count": len(rows),
                "source_type": "dataset2_staging",
            },
            "run_preflight": {
                "model_family": approval_scope.get("model_family"),
                "validation_policy": approval_scope.get("validation_policy"),
                "baseline_accuracy": approval_scope.get("baseline_accuracy"),
                "label_counts": dict(label_counts),
                "split_counts": dict(split_counts),
                "risk_level_counts": dict(risk_counts),
                "feature_key_count": approval_scope.get("feature_key_count"),
                "final_dry_run_manifest_hash": approval_evidence.get("final_dry_run_manifest_hash"),
                "simulated_artifact_manifest_hash": approval_evidence.get("simulated_artifact_manifest_hash"),
                "release_simulation_manifest_hash": approval_evidence.get("release_simulation_manifest_hash"),
                "sample_set_hash": current_sample_set_hash,
                "expected_confirmation_token": "RUN_DATASET2_CONTROLLED_TRAINING_EXECUTION",
                "writes_model_artifact_now": False,
                "writes_file_now": False,
                "executes_training_now": False,
                "training_started_now": False,
                "artifact_path": None,
                "artifact_write_allowed": False,
                "record_bodies_included": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "run_controlled_dataset2_training_execution"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_run_preflight_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_run_preflight_recorded": True,
                "controlled_dataset2_training_execution_run_preflight_ready": ready,
                "can_run_controlled_dataset2_training_execution_now": False,
                "can_prepare_controlled_dataset2_training_execution_run_now": ready,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "run_controlled_dataset2_training_execution"
                    if ready
                    else "resolve_controlled_dataset2_training_execution_run_preflight_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_run_preflight_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

