    def dataset2_controlled_training_execution_run(
        self,
        run_preflight_event_id: int | None = None,
        run_by: str = "operator",
        confirmation_token: str | None = None,
        note: str | None = None,
        limit: int = 1000,
    ) -> dict[str, Any]:
        """Run controlled in-memory Dataset2 training without writing a model artifact."""
        store = SQLiteStore(settings.database_path)
        store.init()
        preflight = self._dataset2_controlled_training_execution_run_preflight_by_id(
            store,
            run_preflight_event_id,
        )
        preflight_decision = (preflight or {}).get("decision") or {}
        preflight_evidence = (preflight or {}).get("evidence") or {}
        run_preflight = (preflight or {}).get("run_preflight") or {}
        resolved_package_id = (preflight or {}).get("package_id")
        rows = self._dataset2_learning_sample_rows(store, resolved_package_id, limit=limit)
        sample_ids = [str(row.get("source_id") or row.get("id") or "") for row in rows]
        current_sample_set_hash = self._stable_hash(sample_ids) if sample_ids else None
        expected_token = "RUN_DATASET2_CONTROLLED_TRAINING_EXECUTION"
        out_of_sample_splits = {"validation", "valid", "test", "out_of_sample"}
        label_counts: Counter[str] = Counter()
        split_counts: Counter[str] = Counter()
        train_label_counts: Counter[str] = Counter()
        out_of_sample_label_counts: Counter[str] = Counter()
        feature_key_counts: Counter[str] = Counter()
        feature_label_rules: dict[str, dict[str, Counter[str]]] = {}
        train_rows: list[dict[str, Any]] = []
        out_of_sample_rows: list[dict[str, Any]] = []
        for row in rows:
            features = json.loads(row.get("features_json") or "{}")
            label = str(row.get("label") or "unknown")
            split = str(features.get("split_tag") or "unknown")
            label_counts[label] += 1
            split_counts[split] += 1
            if split == "train":
                train_rows.append({"label": label, "features": features})
                train_label_counts[label] += 1
                for key, value in sorted(features.items()):
                    if value in (None, "", [], {}):
                        continue
                    key_str = str(key)
                    value_str = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
                    feature_key_counts[key_str] += 1
                    feature_label_rules.setdefault(key_str, {}).setdefault(value_str, Counter())[label] += 1
            elif split in out_of_sample_splits:
                out_of_sample_rows.append({"label": label, "features": features})
                out_of_sample_label_counts[label] += 1
        majority_label = train_label_counts.most_common(1)[0][0] if train_label_counts else None

        def predict(features: dict[str, Any]) -> str | None:
            best_label = majority_label
            best_score = -1
            for key, value in sorted(features.items()):
                value_rules = feature_label_rules.get(str(key))
                if not value_rules:
                    continue
                value_key = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str)
                label_rule = value_rules.get(value_key)
                if not label_rule:
                    continue
                label, score = label_rule.most_common(1)[0]
                if score > best_score:
                    best_label = label
                    best_score = score
            return best_label

        train_correct = sum(1 for item in train_rows if predict(item["features"]) == item["label"])
        out_of_sample_predictions = [
            {"expected": item["label"], "predicted": predict(item["features"])}
            for item in out_of_sample_rows
        ]
        out_of_sample_correct = sum(
            1 for item in out_of_sample_predictions if item["predicted"] == item["expected"]
        )
        train_accuracy = round(train_correct / len(train_rows), 6) if train_rows else None
        out_of_sample_accuracy = (
            round(out_of_sample_correct / len(out_of_sample_rows), 6)
            if out_of_sample_rows
            else None
        )
        model_summary = {
            "model_family": run_preflight.get("model_family") or "local_rule_classifier",
            "algorithm": "feature_value_frequency_classifier",
            "target": "label",
            "majority_label": majority_label,
            "label_counts": dict(label_counts),
            "train_label_counts": dict(train_label_counts),
            "trained_feature_count": len(feature_key_counts),
            "feature_rule_count": sum(len(values) for values in feature_label_rules.values()),
            "record_bodies_included": False,
            "model_artifact_written": False,
            "artifact_path": None,
        }
        model_summary_hash = self._stable_hash(model_summary)
        preflight_ready = (
            preflight
            and preflight.get("status") == "dataset2_controlled_training_execution_run_preflight_ready"
            and preflight_decision.get("controlled_dataset2_training_execution_run_preflight_ready") is True
            and preflight_decision.get("can_prepare_controlled_dataset2_training_execution_run_now") is True
        )
        checks = [
            self._manual_evidence_check(
                "run_preflight_ready",
                "passed" if preflight_ready else "blocked",
                {
                    "run_preflight_event_id": (preflight or {}).get("id"),
                    "run_preflight_status": (preflight or {}).get("status"),
                    "can_prepare_run": preflight_decision.get(
                        "can_prepare_controlled_dataset2_training_execution_run_now"
                    ),
                },
                "ready P81 run preflight",
                "P82 can only run after ready P81 preflight metadata",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P82 requires explicit operator confirmation before in-memory training execution",
            ),
            self._manual_evidence_check(
                "sample_set_hash_matches_preflight",
                (
                    "passed"
                    if bool(current_sample_set_hash)
                    and current_sample_set_hash == preflight_evidence.get("current_sample_set_hash")
                    else "blocked"
                ),
                {
                    "current_sample_set_hash": current_sample_set_hash,
                    "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                },
                "matching sample-set hash",
                "P82 must train on the same Dataset2 sample set verified by P81",
            ),
            self._manual_evidence_check(
                "learning_sample_count_matches_preflight",
                (
                    "passed"
                    if rows
                    and len(rows) == int(preflight_evidence.get("current_learning_sample_count") or 0)
                    else "blocked"
                ),
                {
                    "current_learning_sample_count": len(rows),
                    "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                },
                "matching sample count",
                "P82 must block if Dataset2 learning sample count drifted after P81",
            ),
            self._manual_evidence_check(
                "train_rows_available",
                "passed" if train_rows else "blocked",
                len(train_rows),
                ">0",
                "P82 needs at least one train split row for controlled training execution",
            ),
            self._manual_evidence_check(
                "out_of_sample_rows_available",
                "passed" if out_of_sample_rows else "blocked",
                len(out_of_sample_rows),
                ">0",
                "P82 needs at least one out-of-sample row for controlled validation",
            ),
            self._manual_evidence_check(
                "feature_rules_trained",
                "passed" if feature_key_counts else "blocked",
                {"trained_feature_count": len(feature_key_counts)},
                ">0 trained features",
                "P82 must train an in-memory rule summary from Dataset2 feature columns",
            ),
            self._manual_evidence_check(
                "no_model_artifact_or_file_write",
                "passed",
                {
                    "model_artifact_written": False,
                    "writes_file": False,
                    "artifact_path": None,
                    "record_bodies_included": False,
                },
                "no artifact/file/body writes",
                "P82 records metrics only and must not write model artifacts or files",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 controlled training execution cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        completed = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_execution_run.v1",
            "stage": "V5.6-P82",
            "status": (
                "dataset2_controlled_training_execution_run_completed"
                if completed
                else "dataset2_controlled_training_execution_run_blocked"
            ),
            "generated_at": now,
            "package_id": resolved_package_id,
            "run": {
                "run_by": run_by or "operator",
                "note": note,
                "confirmation_token_matched": confirmation_token == expected_token,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "run_preflight_event_id": (preflight or {}).get("id"),
                "run_approval_id": preflight_evidence.get("run_approval_id"),
                "final_dry_run_review_id": preflight_evidence.get("final_dry_run_review_id"),
                "final_dry_run_event_id": preflight_evidence.get("final_dry_run_event_id"),
                "final_dry_run_manifest_hash": preflight_evidence.get("final_dry_run_manifest_hash"),
                "simulated_artifact_manifest_hash": preflight_evidence.get("simulated_artifact_manifest_hash"),
                "release_simulation_manifest_hash": preflight_evidence.get("release_simulation_manifest_hash"),
                "preflight_sample_set_hash": preflight_evidence.get("current_sample_set_hash"),
                "current_sample_set_hash": current_sample_set_hash,
                "preflight_learning_sample_count": preflight_evidence.get("current_learning_sample_count"),
                "current_learning_sample_count": len(rows),
                "source_type": "dataset2_staging",
            },
            "training_result": {
                "model_family": model_summary["model_family"],
                "algorithm": model_summary["algorithm"],
                "target": "label",
                "model_summary_hash": model_summary_hash,
                "majority_label": majority_label,
                "train_row_count": len(train_rows),
                "out_of_sample_row_count": len(out_of_sample_rows),
                "label_counts": dict(label_counts),
                "split_counts": dict(split_counts),
                "train_label_counts": dict(train_label_counts),
                "out_of_sample_label_counts": dict(out_of_sample_label_counts),
                "trained_feature_count": len(feature_key_counts),
                "feature_rule_count": model_summary["feature_rule_count"],
                "train_accuracy": train_accuracy,
                "out_of_sample_accuracy": out_of_sample_accuracy,
                "model_artifact_written": False,
                "writes_file": False,
                "artifact_path": None,
                "record_bodies_included": False,
                "in_memory_model_trained": completed,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_run_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_execution_run_recorded": True,
                "controlled_dataset2_training_execution_run_completed": completed,
                "in_memory_training_completed": completed,
                "can_prepare_controlled_dataset2_training_execution_run_review_now": completed,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": completed,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "review_controlled_dataset2_training_execution_run"
                    if completed
                    else "resolve_controlled_dataset2_training_execution_run_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_execution_run_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

