    def dataset2_controlled_training_artifact_plan(
        self,
        run_review_id: int | None = None,
        planned_by: str = "operator",
        note: str | None = None,
    ) -> dict[str, Any]:
        """Create a metadata-only Dataset2 model artifact plan after P83 run review."""
        store = SQLiteStore(settings.database_path)
        store.init()
        review = self._dataset2_controlled_training_execution_run_review_by_id(store, run_review_id)
        review_decision = (review or {}).get("decision") or {}
        review_evidence = (review or {}).get("evidence") or {}
        run_review = (review or {}).get("run_review") or {}
        review_ready = (
            review
            and review.get("status") == "dataset2_controlled_training_execution_run_review_accepted"
            and review_decision.get("controlled_dataset2_training_execution_run_review_accepted") is True
            and review_decision.get("can_prepare_controlled_dataset2_training_artifact_plan_now") is True
        )
        artifact_plan_id = f"dataset2-artifact-plan-{self._stable_hash({'run_review_id': (review or {}).get('id'), 'sample_set_hash': review_evidence.get('sample_set_hash'), 'model_summary_hash': review_evidence.get('model_summary_hash')})[:16]}"
        artifact_manifest = {
            "artifact_plan_id": artifact_plan_id,
            "artifact_kind": "local_rule_classifier_summary",
            "model_family": run_review.get("model_family") or "local_rule_classifier",
            "algorithm": run_review.get("algorithm") or "feature_value_frequency_classifier",
            "target": run_review.get("target") or "label",
            "sample_set_hash": review_evidence.get("sample_set_hash"),
            "model_summary_hash": review_evidence.get("model_summary_hash"),
            "learning_sample_count": review_evidence.get("learning_sample_count"),
            "artifact_path": None,
            "artifact_write_allowed_now": False,
            "requires_manual_approval": True,
            "record_bodies_included": False,
        }
        artifact_plan_hash = self._stable_hash(artifact_manifest)
        checks = [
            self._manual_evidence_check(
                "run_review_accepted",
                "passed" if review_ready else "blocked",
                {
                    "run_review_id": (review or {}).get("id"),
                    "run_review_status": (review or {}).get("status"),
                    "can_prepare_artifact_plan": review_decision.get(
                        "can_prepare_controlled_dataset2_training_artifact_plan_now"
                    ),
                },
                "accepted P83 run review",
                "P84 can only plan a future artifact after accepted P83 review evidence",
            ),
            self._manual_evidence_check(
                "model_summary_hash_pinned",
                "passed" if bool(review_evidence.get("model_summary_hash")) else "blocked",
                review_evidence.get("model_summary_hash"),
                "non-empty model_summary_hash",
                "P84 must pin the reviewed in-memory model summary hash",
            ),
            self._manual_evidence_check(
                "sample_set_hash_pinned",
                "passed" if bool(review_evidence.get("sample_set_hash")) else "blocked",
                review_evidence.get("sample_set_hash"),
                "non-empty sample_set_hash",
                "P84 must pin the Dataset2 sample set used for the reviewed run",
            ),
            self._manual_evidence_check(
                "training_metrics_available",
                (
                    "passed"
                    if int(run_review.get("train_row_count") or 0) > 0
                    and int(run_review.get("out_of_sample_row_count") or 0) > 0
                    and int(run_review.get("trained_feature_count") or 0) > 0
                    else "blocked"
                ),
                {
                    "train_row_count": run_review.get("train_row_count"),
                    "out_of_sample_row_count": run_review.get("out_of_sample_row_count"),
                    "trained_feature_count": run_review.get("trained_feature_count"),
                    "out_of_sample_accuracy": run_review.get("out_of_sample_accuracy"),
                },
                "aggregate train/out-of-sample metrics",
                "P84 artifact planning requires aggregate model evidence without record bodies",
            ),
            self._manual_evidence_check(
                "no_artifact_write_now",
                (
                    "passed"
                    if artifact_manifest["artifact_write_allowed_now"] is False
                    and artifact_manifest["artifact_path"] is None
                    and run_review.get("model_artifact_written") is False
                    and run_review.get("writes_file") is False
                    and review_decision.get("model_artifact_written") is False
                    and review_decision.get("writes_file") is False
                    else "blocked"
                ),
                {
                    "artifact_write_allowed_now": artifact_manifest["artifact_write_allowed_now"],
                    "artifact_path": artifact_manifest["artifact_path"],
                    "run_review_model_artifact_written": run_review.get("model_artifact_written"),
                    "run_review_writes_file": run_review.get("writes_file"),
                    "decision_model_artifact_written": review_decision.get("model_artifact_written"),
                    "decision_writes_file": review_decision.get("writes_file"),
                },
                "all artifact/file write flags false",
                "P84 may plan a future artifact but must not write one now",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 artifact planning cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        ready = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_artifact_plan.v1",
            "stage": "V5.6-P84",
            "status": (
                "dataset2_controlled_training_artifact_plan_ready"
                if ready
                else "dataset2_controlled_training_artifact_plan_blocked"
            ),
            "generated_at": now,
            "package_id": (review or {}).get("package_id"),
            "planning": {
                "planned_by": planned_by or "operator",
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "run_review_id": (review or {}).get("id"),
                "run_event_id": review_evidence.get("run_event_id"),
                "run_preflight_event_id": review_evidence.get("run_preflight_event_id"),
                "run_approval_id": review_evidence.get("run_approval_id"),
                "final_dry_run_review_id": review_evidence.get("final_dry_run_review_id"),
                "final_dry_run_manifest_hash": review_evidence.get("final_dry_run_manifest_hash"),
                "simulated_artifact_manifest_hash": review_evidence.get("simulated_artifact_manifest_hash"),
                "release_simulation_manifest_hash": review_evidence.get("release_simulation_manifest_hash"),
                "sample_set_hash": review_evidence.get("sample_set_hash"),
                "learning_sample_count": review_evidence.get("learning_sample_count"),
                "model_summary_hash": review_evidence.get("model_summary_hash"),
                "source_type": "dataset2_staging",
            },
            "artifact_plan": {
                "artifact_plan_id": artifact_plan_id,
                "artifact_plan_hash": artifact_plan_hash,
                "artifact_manifest": artifact_manifest,
                "required_preflight_checks": [
                    "run_review_id_matches",
                    "artifact_plan_hash_matches",
                    "sample_set_hash_matches",
                    "model_summary_hash_matches",
                    "artifact_write_disabled_until_approval",
                    "live_trading_disabled",
                    "explicit_artifact_approval_required",
                ],
                "expected_next_decision": "approved_for_controlled_dataset2_training_artifact_plan_preflight",
                "expected_confirmation_token": "APPROVE_DATASET2_CONTROLLED_TRAINING_ARTIFACT_PLAN",
                "writes_model_artifact_now": False,
                "writes_file_now": False,
                "executes_training_now": False,
                "training_started_now": False,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "request_controlled_dataset2_training_artifact_plan_approval"
                    if ready
                    else "resolve_controlled_dataset2_training_artifact_plan_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_artifact_plan_recorded": True,
                "controlled_dataset2_training_artifact_plan_ready": ready,
                "can_request_controlled_dataset2_training_artifact_plan_approval_now": ready,
                "can_write_model_artifact_now": False,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "request_controlled_dataset2_training_artifact_plan_approval"
                    if ready
                    else "resolve_controlled_dataset2_training_artifact_plan_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_artifact_plan_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

