    def dataset2_controlled_training_artifact_plan_approval(
        self,
        artifact_plan_event_id: int | None = None,
        approved_by: str = "operator",
        approval_decision: str = "approved_for_controlled_dataset2_training_artifact_plan_preflight",
        confirmation_token: str | None = None,
        note: str | None = None,
    ) -> dict[str, Any]:
        """Record metadata-only approval for a future Dataset2 artifact plan preflight."""
        store = SQLiteStore(settings.database_path)
        store.init()
        plan = self._dataset2_controlled_training_artifact_plan_by_id(store, artifact_plan_event_id)
        plan_decision = (plan or {}).get("decision") or {}
        plan_evidence = (plan or {}).get("evidence") or {}
        artifact_plan = (plan or {}).get("artifact_plan") or {}
        artifact_manifest = artifact_plan.get("artifact_manifest") or {}
        expected_decision = "approved_for_controlled_dataset2_training_artifact_plan_preflight"
        expected_token = "APPROVE_DATASET2_CONTROLLED_TRAINING_ARTIFACT_PLAN"
        plan_ready = (
            plan
            and plan.get("status") == "dataset2_controlled_training_artifact_plan_ready"
            and plan_decision.get("controlled_dataset2_training_artifact_plan_ready") is True
            and plan_decision.get("can_request_controlled_dataset2_training_artifact_plan_approval_now") is True
        )
        no_artifact_write = (
            artifact_plan.get("writes_model_artifact_now") is False
            and artifact_plan.get("writes_file_now") is False
            and artifact_plan.get("executes_training_now") is False
            and artifact_plan.get("training_started_now") is False
            and artifact_manifest.get("artifact_write_allowed_now") is False
            and artifact_manifest.get("artifact_path") is None
            and plan_decision.get("can_write_model_artifact_now") is False
            and plan_decision.get("model_artifact_written") is False
            and plan_decision.get("writes_file") is False
        )
        checks = [
            self._manual_evidence_check(
                "artifact_plan_ready",
                "passed" if plan_ready else "blocked",
                {
                    "artifact_plan_event_id": (plan or {}).get("id"),
                    "artifact_plan_status": (plan or {}).get("status"),
                    "can_request_approval": plan_decision.get(
                        "can_request_controlled_dataset2_training_artifact_plan_approval_now"
                    ),
                },
                "ready P84 artifact plan",
                "P85 can only approve a ready P84 artifact plan for a later preflight",
            ),
            self._manual_evidence_check(
                "approval_decision_allowed",
                "passed" if approval_decision == expected_decision else "blocked",
                approval_decision,
                expected_decision,
                "P85 approval can only authorize a later artifact plan preflight",
            ),
            self._manual_evidence_check(
                "confirmation_token_required",
                "passed" if confirmation_token == expected_token else "blocked",
                {"token_matched": confirmation_token == expected_token},
                expected_token,
                "P85 requires explicit operator confirmation before preflight approval metadata is recorded",
            ),
            self._manual_evidence_check(
                "artifact_plan_hash_pinned",
                "passed" if bool(artifact_plan.get("artifact_plan_hash")) else "blocked",
                artifact_plan.get("artifact_plan_hash"),
                "non-empty artifact_plan_hash",
                "P85 must preserve the reviewed artifact plan hash",
            ),
            self._manual_evidence_check(
                "model_and_sample_hashes_pinned",
                (
                    "passed"
                    if bool(plan_evidence.get("model_summary_hash"))
                    and bool(plan_evidence.get("sample_set_hash"))
                    else "blocked"
                ),
                {
                    "model_summary_hash": plan_evidence.get("model_summary_hash"),
                    "sample_set_hash": plan_evidence.get("sample_set_hash"),
                },
                "model_summary_hash and sample_set_hash",
                "P85 must pin both model and Dataset2 sample evidence before later artifact preflight",
            ),
            self._manual_evidence_check(
                "no_artifact_write_now",
                "passed" if no_artifact_write else "blocked",
                {
                    "writes_model_artifact_now": artifact_plan.get("writes_model_artifact_now"),
                    "writes_file_now": artifact_plan.get("writes_file_now"),
                    "executes_training_now": artifact_plan.get("executes_training_now"),
                    "training_started_now": artifact_plan.get("training_started_now"),
                    "artifact_write_allowed_now": artifact_manifest.get("artifact_write_allowed_now"),
                    "artifact_path": artifact_manifest.get("artifact_path"),
                    "decision_can_write_model_artifact_now": plan_decision.get("can_write_model_artifact_now"),
                },
                "all artifact/file/training flags false",
                "P85 records approval metadata only and must not write artifacts or files",
            ),
            self._manual_evidence_check(
                "live_trading_disabled",
                "passed" if settings.enable_live_trading is False else "blocked",
                settings.enable_live_trading,
                False,
                "Dataset2 artifact plan approval cannot proceed while live trading is enabled",
            ),
        ]
        blocked = [check for check in checks if check["status"] == "blocked"]
        accepted = not blocked
        now = datetime.now().isoformat(timespec="seconds")
        payload = {
            "schema_version": "dataset2_controlled_training_artifact_plan_approval.v1",
            "stage": "V5.6-P85",
            "status": (
                "dataset2_controlled_training_artifact_plan_approval_accepted"
                if accepted
                else "dataset2_controlled_training_artifact_plan_approval_blocked"
            ),
            "generated_at": now,
            "package_id": (plan or {}).get("package_id"),
            "approval": {
                "approved_by": approved_by or "operator",
                "approval_decision": approval_decision,
                "approved_for_controlled_dataset2_training_artifact_plan_preflight": (
                    approval_decision == expected_decision
                ),
                "confirmation_token_matched": confirmation_token == expected_token,
                "note": note,
                "record_bodies_included": False,
                "review_only": True,
                "simulation_only": True,
            },
            "evidence": {
                "artifact_plan_event_id": (plan or {}).get("id"),
                "run_review_id": plan_evidence.get("run_review_id"),
                "run_event_id": plan_evidence.get("run_event_id"),
                "artifact_plan_id": artifact_plan.get("artifact_plan_id"),
                "artifact_plan_hash": artifact_plan.get("artifact_plan_hash"),
                "sample_set_hash": plan_evidence.get("sample_set_hash"),
                "learning_sample_count": plan_evidence.get("learning_sample_count"),
                "model_summary_hash": plan_evidence.get("model_summary_hash"),
                "source_type": "dataset2_staging",
            },
            "approval_scope": {
                "allowed_next_stage": "controlled_dataset2_training_artifact_plan_preflight",
                "expected_confirmation_token": "PREPARE_DATASET2_CONTROLLED_TRAINING_ARTIFACT_PREFLIGHT",
                "artifact_plan_id": artifact_plan.get("artifact_plan_id"),
                "artifact_plan_hash": artifact_plan.get("artifact_plan_hash"),
                "artifact_kind": artifact_manifest.get("artifact_kind"),
                "model_family": artifact_manifest.get("model_family"),
                "algorithm": artifact_manifest.get("algorithm"),
                "target": artifact_manifest.get("target"),
                "sample_set_hash": plan_evidence.get("sample_set_hash"),
                "model_summary_hash": plan_evidence.get("model_summary_hash"),
                "artifact_write_allowed_now": False,
                "writes_model_artifact_now": False,
                "writes_file_now": False,
                "executes_training_now": False,
                "training_started_now": False,
                "requires_manual_approval": True,
            },
            "checks": checks,
            "summary": {
                "passed_check_count": len([check for check in checks if check["status"] == "passed"]),
                "warning_check_count": len([check for check in checks if check["status"] == "warning"]),
                "blocked_check_count": len(blocked),
                "next_required_action": (
                    "prepare_controlled_dataset2_training_artifact_preflight"
                    if accepted
                    else "resolve_controlled_dataset2_training_artifact_plan_approval_blocks"
                ),
            },
            "decision": {
                "controlled_dataset2_training_artifact_plan_approval_recorded": True,
                "controlled_dataset2_training_artifact_plan_approval_accepted": accepted,
                "can_prepare_controlled_dataset2_training_artifact_preflight_now": accepted,
                "can_write_model_artifact_now": False,
                "can_execute_dataset2_training_now": False,
                "can_start_training_now": False,
                "training_started_now": False,
                "model_artifact_written": False,
                "writes_database_now": False,
                "writes_existing_event_now": True,
                "writes_staging_records_now": False,
                "mutates_staging_records_now": False,
                "writes_learning_samples_now": False,
                "writes_source_dataset": False,
                "writes_file": False,
                "live_trading_enabled": settings.enable_live_trading,
                "next_required_action": (
                    "prepare_controlled_dataset2_training_artifact_preflight"
                    if accepted
                    else "resolve_controlled_dataset2_training_artifact_plan_approval_blocks"
                ),
            },
            "safety_summary": self._safety_summary(writes_existing_event_now=True),
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        with store.connect() as conn:
            cursor = conn.execute(
                "INSERT INTO events (event_type, payload_json) VALUES (?, ?)",
                (
                    self.dataset2_controlled_training_artifact_plan_approval_event_type,
                    json.dumps(payload, ensure_ascii=False, sort_keys=True, default=str),
                ),
            )
            event_id = int(cursor.lastrowid)
        return {"event_id": event_id, **payload}

