    def list_dataset2_controlled_training_artifact_write_execution_final_write_execution_final_final_final_final_preflights(
        self,
        limit: int = 20,
    ) -> list[dict[str, Any]]:
        store = SQLiteStore(settings.database_path)
        store.init()
        rows = store.fetch_all(
            """
            SELECT id, event_type, payload_json, created_at
            FROM events
            WHERE event_type = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (
                self.dataset2_controlled_training_artifact_write_execution_final_write_execution_final_final_final_final_preflight_event_type,
                max(1, min(limit, 100)),
            ),
        )
        return [self._event_payload(row) for row in rows]

