    def list_staging_cleanup_execution_controlled_apply_execution_plan_execution_final_execution_execution_execution_execution_approvals(
        self,
        limit: int = 20,
    ) -> list[dict[str, Any]]:
        store = SQLiteStore(settings.database_path)
        store.init()
        rows = store.fetch_all(
            """
            SELECT id, event_type, payload_json, created_at
            FROM events
            WHERE event_type = ?
            ORDER BY id DESC
            LIMIT ?
            """,
            (
                self.staging_cleanup_execution_controlled_apply_execution_plan_execution_final_execution_execution_execution_execution_approval_event_type,
                max(1, min(limit, 100)),
            ),
        )
        approvals: list[dict[str, Any]] = []
        for row in rows:
            payload = json.loads(row.pop("payload_json") or "{}")
            approvals.append(
                {
                    "id": row["id"],
                    "event_type": row["event_type"],
                    "created_at": row["created_at"],
                    **payload,
                }
            )
        return approvals

