    def _dataset2_learning_sample_rows(
        self,
        store: SQLiteStore,
        package_id: str | None,
        limit: int = 1000,
    ) -> list[dict[str, Any]]:
        if package_id:
            return store.fetch_all(
                """
                SELECT *
                FROM learning_samples
                WHERE source_type = 'dataset2_staging'
                  AND source_id LIKE ?
                ORDER BY source_id
                LIMIT ?
                """,
                (f"{package_id}:%", max(1, min(limit, 1000))),
            )
        return store.fetch_all(
            """
            SELECT *
            FROM learning_samples
            WHERE source_type = 'dataset2_staging'
            ORDER BY source_id
            LIMIT ?
            """,
            (max(1, min(limit, 1000)),),
        )

    def _staging_rows_for_promotion(
        self,
        store: SQLiteStore,
        package_id: str | None,
        limit: int = 1000,
    ) -> list[dict[str, Any]]:
        if not package_id:
            return []
        rows = store.fetch_all(
            """
            SELECT *
            FROM dataset2_staging_records
            WHERE package_id = ?
            ORDER BY id
            LIMIT ?
            """,
            (package_id, max(1, min(limit, 1000))),
        )
        return [self._staging_row(row) for row in rows]

    def _existing_learning_sample_source_ids(
        self,
        store: SQLiteStore,
        source_ids: list[str],
    ) -> list[str]:
        if not source_ids:
            return []
        existing: list[str] = []
        for index in range(0, len(source_ids), 500):
            batch = source_ids[index : index + 500]
            placeholders = ",".join("?" for _ in batch)
            rows = store.fetch_all(
                f"""
                SELECT source_id
                FROM learning_samples
                WHERE source_type = 'dataset2_staging'
                  AND source_id IN ({placeholders})
                ORDER BY source_id
                """,
                tuple(batch),
            )
            existing.extend(str(row["source_id"]) for row in rows if row.get("source_id"))
        return sorted(set(existing))

    def _learning_sample_projection(self, row: dict[str, Any]) -> dict[str, Any]:
        normalized = row.get("normalized") or {}
        package_id = str(row.get("package_id") or "")
        pattern_id = str(row.get("pattern_id") or normalized.get("pattern_id") or "")
        source_id = f"{package_id}:{pattern_id}"
        sample_id = f"dataset2-{self._stable_hash({'source_type': 'dataset2_staging', 'source_id': source_id})[:24]}"
        return_pct = self._float_or_none(normalized.get("forward_return_5d"))
        label = self._dataset2_learning_label(str(row.get("action_label") or ""), return_pct)
        feature_keys = [
            key
            for key in [
                "category",
                "timeframe",
                "market_phase",
                "preconditions",
                "observable_features",
                "trigger_conditions",
                "confirmation_signals",
                "negative_filters",
                "invalidation_conditions",
                "expected_bias",
                "action_label",
                "risk_level",
                "confidence",
                "split_tag",
                "benchmark_return",
                "max_favorable_excursion",
                "max_adverse_excursion",
            ]
            if key in normalized
        ]
        lessons = [
            value
            for value in [
                normalized.get("evidence_summary"),
                normalized.get("training_notes"),
                normalized.get("rule_logic"),
            ]
            if value
        ]
        return {
            "sample_id": sample_id,
            "source_type": "dataset2_staging",
            "source_id": source_id,
            "pattern_id": pattern_id,
            "symbol": normalized.get("stock_code") or row.get("stock_code"),
            "name": normalized.get("pattern_name") or pattern_id,
            "label": label,
            "outcome_score": return_pct,
            "entry_price": self._float_or_none(normalized.get("entry_price")),
            "exit_price": self._float_or_none(normalized.get("exit_price")),
            "return_pct": return_pct,
            "risk_level": row.get("risk_level") or normalized.get("risk_level"),
            "rating": normalized.get("confidence"),
            "action_label": row.get("action_label"),
            "split_tag": row.get("split_tag"),
            "feature_keys": feature_keys,
            "lesson_count": len(lessons),
            "raw_keys": [
                key
                for key in [
                    "dataset_version",
                    "source_id",
                    "source_document",
                    "signal_date",
                    "model_targets",
                ]
                if key in normalized
            ],
        }

    def _learning_sample_insert_row(self, row: dict[str, Any]) -> dict[str, Any]:
        normalized = row.get("normalized") or {}
        projection = self._learning_sample_projection(row)
        features = {
            key: normalized.get(key)
            for key in projection["feature_keys"]
            if key in normalized
        }
        features.update(
            {
                "dataset2_package_id": row.get("package_id"),
                "pattern_id": projection["pattern_id"],
                "action_label": row.get("action_label"),
                "split_tag": row.get("split_tag"),
                "signal_date": normalized.get("signal_date"),
                "review_only": True,
                "simulation_only": True,
                "live_trading_enabled": settings.enable_live_trading,
            }
        )
        lessons = [
            {"field": key, "text": normalized.get(key)}
            for key in ["evidence_summary", "training_notes", "rule_logic"]
            if normalized.get(key)
        ]
        raw = {
            "dataset_version": normalized.get("dataset_version"),
            "source_document": normalized.get("source_document"),
            "source_id": normalized.get("source_id"),
            "staging_record_id": row.get("id"),
            "package_id": row.get("package_id"),
            "normalized_records_hash": row.get("normalized_records_hash"),
            "model_targets": normalized.get("model_targets") or {},
            "review_only": True,
            "simulation_only": True,
            "live_trading_enabled": settings.enable_live_trading,
        }
        return {
            "id": projection["sample_id"],
            "source_type": projection["source_type"],
            "source_id": projection["source_id"],
            "symbol": projection["symbol"],
            "name": projection["name"],
            "label": projection["label"],
            "outcome_score": projection["outcome_score"] or 0.0,
            "entry_price": projection["entry_price"],
            "exit_price": projection["exit_price"],
            "return_pct": projection["return_pct"],
            "risk_level": projection["risk_level"],
            "rating": projection["rating"],
            "features": features,
            "lessons": lessons,
            "raw": raw,
        }

    def _dataset2_learning_label(self, action_label: str, return_pct: float | None) -> str:
        positive_trade_actions = {"SIM_BUY_CANDIDATE", "HOLD_OR_TRAIL", "WAIT_CONFIRMATION"}
        defensive_actions = {"REDUCE_OR_EXIT", "AVOID_OR_WAIT", "RISK_ALERT", "NO_TRADE"}
        if action_label in positive_trade_actions:
            return "method_success" if (return_pct or 0.0) > 0 else "failure"
        if action_label in defensive_actions:
            return "risk_failure" if (return_pct or 0.0) <= 0 else "failure"
        return "training_candidate"

    def _balanced_class_weights(self, label_counts: Counter[str]) -> dict[str, float]:
        usable = {label: count for label, count in label_counts.items() if label and label != "unknown" and count > 0}
        if not usable:
            return {}
        total = sum(usable.values())
        class_count = len(usable)
        return {
            label: round(total / (class_count * count), 6)
            for label, count in sorted(usable.items())
        }

    def _float_or_none(self, value: Any) -> float | None:
        if value is None or value == "":
            return None
        try:
            return float(value)
        except (TypeError, ValueError):
            return None

    def _cleanup_preflight_lock_key(self, manual_approval: dict[str, Any], staging_count: int) -> str:
        seed = {
            "manual_approval_id": manual_approval.get("id"),
            "approval_plan_id": manual_approval.get("approval_plan_id"),
            "package_id": manual_approval.get("package_id"),
            "evidence_package_hash": (manual_approval.get("evidence_summary") or {}).get("evidence_package_hash"),
            "staging_count": staging_count,
        }
        digest = hashlib.sha256(json.dumps(seed, sort_keys=True, default=str).encode("utf-8")).hexdigest()
        return f"dataset2-cleanup-preflight-{digest[:16]}"

    def _cleanup_execution_dry_run_simulation(self, store: SQLiteStore, package_id: str | None) -> dict[str, Any]:
        clauses: list[str] = []
        params: list[Any] = []
        if package_id:
            clauses.append("package_id = ?")
            params.append(package_id)
        where = f"WHERE {' AND '.join(clauses)}" if clauses else ""
        rows = store.fetch_all(
            f"""
            SELECT package_id, action_label, risk_level, split_tag, quality_flags_json, cleanup_operations_json
            FROM dataset2_staging_records
            {where}
            ORDER BY id
            LIMIT 1000
            """,
            tuple(params),
        )
        operation_counts: Counter[str] = Counter()
        field_counts: Counter[str] = Counter()
        quality_flag_counts: Counter[str] = Counter()
        action_counts: Counter[str] = Counter()
        risk_counts: Counter[str] = Counter()
        split_counts: Counter[str] = Counter()
        records_with_operations = 0
        records_with_quality_flags = 0
        for row in rows:
            action_counts[str(row.get("action_label") or "unknown")] += 1
            risk_counts[str(row.get("risk_level") or "unknown")] += 1
            split_counts[str(row.get("split_tag") or "unknown")] += 1
            quality_flags = json.loads(row.get("quality_flags_json") or "[]")
            operations = json.loads(row.get("cleanup_operations_json") or "[]")
            if quality_flags:
                records_with_quality_flags += 1
            if operations:
                records_with_operations += 1
            for flag in quality_flags:
                quality_flag_counts[str(flag)] += 1
            for operation in operations:
                operation_counts[str(operation.get("operation") or "unknown")] += 1
                field_counts[str(operation.get("field") or "unknown")] += 1
        learning_count = self._learning_sample_count(store)
        return {
            "package_id": package_id,
            "candidate_record_count": len(rows),
            "records_with_operations": records_with_operations,
            "records_with_quality_flags": records_with_quality_flags,
            "simulated_mutation_count": sum(operation_counts.values()),
            "operation_counts": dict(operation_counts),
            "field_counts": dict(field_counts),
            "quality_flag_counts": dict(quality_flag_counts),
            "action_label_counts": dict(action_counts),
            "risk_level_counts": dict(risk_counts),
            "split_counts": dict(split_counts),
            "learning_sample_count_before": learning_count,
            "expected_learning_sample_count_after": learning_count,
            "writes_staging_records_now": False,
            "writes_learning_samples_now": False,
            "mutates_staging_records_now": False,
            "contains_sql": False,
            "contains_executable_code": False,
            "can_execute_now": False,
            "record_bodies_included": False,
            "affected_rows_body_included": False,
            "review_only": True,
            "simulation_only": True,
        }

