    def _controlled_apply_preflight_snapshot(
        self,
        store: SQLiteStore,
        approval: dict[str, Any],
    ) -> dict[str, Any]:
        scope = approval.get("approval_scope") or {}
        simulation = approval.get("simulation_summary") or {}
        package_id = scope.get("package_id") or approval.get("package_id")
        current_staging_count = self._staging_record_count(store, package_id)
        current_learning_count = self._learning_sample_count(store)
        approved_staging_count = int(
            simulation.get("staging_record_count_before")
            or scope.get("staging_record_count")
            or current_staging_count
            or 0
        )
        return {
            "package_id": package_id,
            "lock_key": scope.get("lock_key"),
            "apply_approval_id": approval.get("id"),
            "apply_review_id": approval.get("apply_review_id"),
            "apply_dry_run_id": approval.get("apply_dry_run_id"),
            "controlled_preflight_id": approval.get("controlled_preflight_id"),
            "controlled_approval_id": approval.get("controlled_approval_id"),
            "controlled_review_id": approval.get("controlled_review_id"),
            "controlled_dry_run_id": approval.get("controlled_dry_run_id"),
            "staging_record_count": current_staging_count,
            "expected_staging_record_count_after": current_staging_count,
            "approved_staging_record_count": approved_staging_count,
            "learning_sample_count": current_learning_count,
            "expected_learning_sample_count_after": current_learning_count,
            "automated_operation_count": scope.get("automated_operation_count", 0),
            "manual_operation_count": scope.get("manual_operation_count", 0),
            "simulated_mutation_count": scope.get("simulated_mutation_count", 0),
            "transaction_required": True,
            "rollback_required": True,
            "rollback_plan": [
                "open_transaction_before_any_future_apply",
                "verify_lock_key_and_counts_before_future_apply",
                "rollback_transaction_on_any_future_apply_error",
                "keep_learning_samples_unchanged",
            ],
            "allowed_tables": scope.get("allowed_tables") or ["dataset2_staging_records"],
            "forbidden_tables": scope.get("forbidden_tables") or ["learning_samples"],
            "allowed_next_stage": "controlled_cleanup_apply_execution_dry_run",
            "contains_sql": False,
            "contains_executable_code": False,
            "can_execute_now": False,
            "record_bodies_included": False,
            "affected_rows_body_included": False,
            "writes_staging_records_now": False,
            "writes_learning_samples_now": False,
            "mutates_staging_records_now": False,
            "review_only": True,
            "simulation_only": True,
        }

    def _controlled_apply_preflight_checks(
        self,
        approval: dict[str, Any],
        preflight: dict[str, Any],
        requested_by: str,
        preflight_decision: str,
    ) -> list[dict[str, Any]]:
        decision = approval.get("decision") or {}
        summary = approval.get("summary") or {}
        blocked_check_count = int(summary.get("blocked_check_count") or 0)
        allowed_decisions = {
            "prepared_for_controlled_cleanup_apply_execution_dry_run",
            "needs_revision",
            "rejected",
        }
        staging_count = int(preflight.get("staging_record_count") or 0)
        approved_staging_count = int(preflight.get("approved_staging_record_count") or 0)
        return [
            self._manual_evidence_check(
                "apply_approval_available",
                "passed" if approval.get("id") else "blocked",
                approval.get("id"),
                "existing controlled cleanup apply execution approval",
                "P26 preflight must reference an existing P25 approval event",
            ),
            self._manual_evidence_check(
                "apply_approval_ready_for_preflight",
                "passed"
                if approval.get("status") == "controlled_cleanup_apply_execution_approval_ready_for_preflight"
                and decision.get("controlled_cleanup_apply_execution_approval_accepted") is True
                and decision.get("can_generate_controlled_cleanup_apply_execution_preflight_now") is True
                else "blocked",
                {
                    "status": approval.get("status"),
                    "accepted": decision.get("controlled_cleanup_apply_execution_approval_accepted"),
                    "can_generate_preflight": decision.get(
                        "can_generate_controlled_cleanup_apply_execution_preflight_now"
                    ),
                },
                "ready_for_preflight",
                "only an accepted P25 apply approval can enter P26 preflight",
            ),
            self._manual_evidence_check(
                "source_approval_blocked_checks_clear",
                "passed" if blocked_check_count == 0 else "blocked",
                blocked_check_count,
                0,
                "P25 approval checks must have no blocked items",
            ),
            self._manual_evidence_check(
                "lock_key_present",
                "passed" if bool(preflight.get("lock_key")) else "blocked",
                preflight.get("lock_key"),
                "non-empty lock key",
                "future apply dry-run must be traceable to the approved lock key",
            ),
            self._manual_evidence_check(
                "staging_count_matches_approval",
                "passed" if staging_count == approved_staging_count and staging_count > 0 else "blocked",
                {"current": staging_count, "approved": approved_staging_count},
                "matching nonzero counts",
                "current staging count must still match the approved aggregate scope",
            ),
            self._manual_evidence_check(
                "transaction_and_rollback_required",
                "passed" if preflight.get("transaction_required") and preflight.get("rollback_required") else "blocked",
                {
                    "transaction_required": preflight.get("transaction_required"),
                    "rollback_required": preflight.get("rollback_required"),
                    "rollback_plan": preflight.get("rollback_plan"),
                },
                "transaction and rollback required",
                "future apply dry-run must retain transaction and rollback gates",
            ),
            self._manual_evidence_check(
                "table_scope_limited",
                "passed"
                if preflight.get("allowed_tables") == ["dataset2_staging_records"]
                and "learning_samples" in (preflight.get("forbidden_tables") or [])
                else "blocked",
                {
                    "allowed_tables": preflight.get("allowed_tables"),
                    "forbidden_tables": preflight.get("forbidden_tables"),
                },
                "dataset2_staging_records only; learning_samples forbidden",
                "P26 preflight can only scope future apply work to staging records",
            ),
            self._manual_evidence_check(
                "preflight_contains_no_executable_payload",
                "passed"
                if not preflight.get("contains_sql")
                and not preflight.get("contains_executable_code")
                and not preflight.get("can_execute_now")
                else "blocked",
                {
                    "contains_sql": bool(preflight.get("contains_sql")),
                    "contains_executable_code": bool(preflight.get("contains_executable_code")),
                    "can_execute_now": bool(preflight.get("can_execute_now")),
                },
                "all false",
                "P26 preflight cannot include executable SQL, runnable code, or execution permission",
            ),
            self._manual_evidence_check(
                "aggregate_only_no_record_bodies",
                "passed"
                if preflight.get("record_bodies_included") is False
                and preflight.get("affected_rows_body_included") is False
                else "blocked",
                {
                    "record_bodies_included": preflight.get("record_bodies_included"),
                    "affected_rows_body_included": preflight.get("affected_rows_body_included"),
                },
                "no record bodies",
                "controlled apply preflight may store aggregate metadata only",
            ),
            self._manual_evidence_check(
                "learning_samples_unchanged",
                "passed"
                if preflight.get("learning_sample_count") == preflight.get("expected_learning_sample_count_after")
                else "blocked",
                {
                    "before": preflight.get("learning_sample_count"),
                    "expected_after": preflight.get("expected_learning_sample_count_after"),
                },
                "unchanged",
                "P26 preflight cannot write or project writes to learning_samples",
            ),
            self._manual_evidence_check(
                "preflight_metadata_present",
                "passed" if bool(requested_by) and preflight_decision in allowed_decisions else "blocked",
                {"requested_by_present": bool(requested_by), "preflight_decision": preflight_decision},
                sorted(allowed_decisions),
                "operator preflight metadata must be explicit and constrained",
            ),
            self._manual_evidence_check(
                "preflight_decision_allows_dry_run_only",
                "passed"
                if preflight_decision == "prepared_for_controlled_cleanup_apply_execution_dry_run"
                else "blocked",
                preflight_decision,
                "prepared_for_controlled_cleanup_apply_execution_dry_run",
                "needs_revision or rejected preflights cannot advance to later dry-run",
            ),
            self._manual_evidence_check(
                "source_approval_kept_execution_blocked",
                "passed"
                if decision.get("cleanup_execution_approved_now") is False
                and decision.get("cleanup_application_allowed_now") is False
                and decision.get("cleanup_executed_now") is False
                and decision.get("can_execute_cleanup_now") is False
                and decision.get("writes_learning_samples_now") is False
                and decision.get("training_started_now") is False
                else "blocked",
                {
                    "cleanup_execution_approved_now": decision.get("cleanup_execution_approved_now"),
                    "cleanup_application_allowed_now": decision.get("cleanup_application_allowed_now"),
                    "cleanup_executed_now": decision.get("cleanup_executed_now"),
                    "can_execute_cleanup_now": decision.get("can_execute_cleanup_now"),
                    "writes_learning_samples_now": decision.get("writes_learning_samples_now"),
                    "training_started_now": decision.get("training_started_now"),
                },
                "all false",
                "P25 approval must not have executed cleanup or training",
            ),
            self._manual_evidence_check(
                "cleanup_and_training_remain_blocked",
                "passed",
                {
                    "cleanup_execution_approved_now": False,
                    "cleanup_application_allowed_now": False,
                    "cleanup_executed_now": False,
                    "can_execute_cleanup_now": False,
                    "writes_learning_samples_now": False,
                    "training_started_now": False,
                },
                "all false",
                "P26 records apply preflight metadata only; cleanup execution and training stay blocked",
            ),
        ]

