    def _controlled_apply_execution_plan_execution_final_approval_checks(
        self,
        review: dict[str, Any],
        approval_scope: dict[str, Any],
        approved_by: str,
        approval_decision: str,
    ) -> list[dict[str, Any]]:
        summary = review.get("summary") or {}
        decision = review.get("decision") or {}
        dry_run_summary = review.get("dry_run_summary") or {}
        blocked_check_count = int(summary.get("blocked_check_count") or 0)
        allowed_decisions = {
            "approved_for_controlled_cleanup_apply_execution_plan_execution_final_preflight",
            "needs_revision",
            "rejected",
        }
        return [
            self._manual_evidence_check(
                "apply_execution_plan_execution_dry_run_review_available",
                "passed" if review.get("id") else "blocked",
                review.get("id"),
                "existing controlled cleanup apply execution plan execution dry-run review",
                "P37 final approval must reference an existing P36 review event",
            ),
            self._manual_evidence_check(
                "apply_execution_plan_execution_dry_run_review_accepted",
                "passed"
                if review.get("status")
                == "controlled_cleanup_apply_execution_plan_execution_dry_run_review_accepted"
                and decision.get("controlled_cleanup_apply_execution_plan_execution_dry_run_review_accepted")
                is True
                and decision.get(
                    "controlled_cleanup_apply_execution_plan_execution_review_ready_for_final_approval"
                )
                is True
                else "blocked",
                {
                    "status": review.get("status"),
                    "accepted": decision.get(
                        "controlled_cleanup_apply_execution_plan_execution_dry_run_review_accepted"
                    ),
                    "ready_for_final_approval": decision.get(
                        "controlled_cleanup_apply_execution_plan_execution_review_ready_for_final_approval"
                    ),
                },
                "accepted and ready_for_final_approval",
                "only an accepted P36 review can enter final approval metadata",
            ),
            self._manual_evidence_check(
                "source_review_blocked_checks_clear",
                "passed" if blocked_check_count == 0 else "blocked",
                blocked_check_count,
                0,
                "P36 review checks must have no blocked items",
            ),
            self._manual_evidence_check(
                "approval_scope_has_final_preflight_gate",
                "passed"
                if approval_scope.get("requires_preflight")
                and approval_scope.get("allowed_next_stage")
                == "controlled_cleanup_apply_execution_plan_execution_final_preflight"
                else "blocked",
                {
                    "requires_preflight": approval_scope.get("requires_preflight"),
                    "allowed_next_stage": approval_scope.get("allowed_next_stage"),
                },
                "final preflight required",
                "P37 final approval can only authorize a later final preflight gate",
            ),
            self._manual_evidence_check(
                "lock_key_present",
                "passed" if bool(approval_scope.get("lock_key")) else "blocked",
                approval_scope.get("lock_key"),
                "non-empty lock key",
                "P37 final approval must retain the apply execution plan execution lock key",
            ),
            self._manual_evidence_check(
                "aggregate_apply_execution_plan_execution_simulation_present",
                "passed" if int(approval_scope.get("simulated_mutation_count") or 0) > 0 else "blocked",
                approval_scope.get("simulated_mutation_count"),
                ">0",
                "final approval metadata needs aggregate simulated apply execution plan execution impact",
            ),
            self._manual_evidence_check(
                "manual_backfill_separated",
                "warning" if int(approval_scope.get("manual_operation_count") or 0) > 0 else "passed",
                {
                    "manual_operation_count": approval_scope.get("manual_operation_count"),
                    "manual_backfill_required": int(approval_scope.get("manual_operation_count") or 0) > 0,
                },
                "manual operations tracked separately",
                "manual backfill remains a future review item and is not executed by this final approval",
            ),
            self._manual_evidence_check(
                "transaction_and_rollback_required",
                "passed"
                if approval_scope.get("requires_transaction") and approval_scope.get("requires_rollback")
                else "blocked",
                {
                    "requires_transaction": approval_scope.get("requires_transaction"),
                    "requires_rollback": approval_scope.get("requires_rollback"),
                },
                "transaction and rollback required",
                "future final preflight cannot proceed without transaction and rollback requirements",
            ),
            self._manual_evidence_check(
                "table_scope_limited",
                "passed"
                if approval_scope.get("allowed_tables") == ["dataset2_staging_records"]
                and "learning_samples" in (approval_scope.get("forbidden_tables") or [])
                else "blocked",
                {
                    "allowed_tables": approval_scope.get("allowed_tables"),
                    "forbidden_tables": approval_scope.get("forbidden_tables"),
                },
                "dataset2_staging_records only; learning_samples forbidden",
                "P37 final approval can only scope future work to staging records",
            ),
            self._manual_evidence_check(
                "source_summary_contains_no_executable_payload",
                "passed"
                if not dry_run_summary.get("contains_sql")
                and not dry_run_summary.get("contains_executable_code")
                and not dry_run_summary.get("can_execute_now")
                else "blocked",
                {
                    "contains_sql": bool(dry_run_summary.get("contains_sql")),
                    "contains_executable_code": bool(dry_run_summary.get("contains_executable_code")),
                    "can_execute_now": bool(dry_run_summary.get("can_execute_now")),
                },
                "all false",
                "P36 source review cannot contain executable payloads",
            ),
            self._manual_evidence_check(
                "approval_scope_contains_no_executable_payload",
                "passed"
                if not approval_scope.get("contains_sql")
                and not approval_scope.get("contains_executable_code")
                and not approval_scope.get("can_execute_now")
                else "blocked",
                {
                    "contains_sql": bool(approval_scope.get("contains_sql")),
                    "contains_executable_code": bool(approval_scope.get("contains_executable_code")),
                    "can_execute_now": bool(approval_scope.get("can_execute_now")),
                },
                "all false",
                "P37 final approval scope must not contain SQL, runnable code, or execution permission",
            ),
            self._manual_evidence_check(
                "aggregate_only_no_record_bodies",
                "passed"
                if dry_run_summary.get("record_bodies_included") is False
                and dry_run_summary.get("affected_rows_body_included") is False
                and approval_scope.get("record_bodies_included") is False
                and approval_scope.get("affected_rows_body_included") is False
                else "blocked",
                {
                    "source_record_bodies_included": dry_run_summary.get("record_bodies_included"),
                    "affected_rows_body_included": dry_run_summary.get("affected_rows_body_included"),
                    "approval_scope_record_bodies_included": approval_scope.get("record_bodies_included"),
                    "approval_scope_affected_rows_body_included": approval_scope.get(
                        "affected_rows_body_included"
                    ),
                },
                "no record bodies",
                "controlled final approval may store aggregate metadata only",
            ),
            self._manual_evidence_check(
                "learning_samples_unchanged",
                "passed"
                if approval_scope.get("learning_sample_count_before")
                == approval_scope.get("expected_learning_sample_count_after")
                else "blocked",
                {
                    "before": approval_scope.get("learning_sample_count_before"),
                    "expected_after": approval_scope.get("expected_learning_sample_count_after"),
                },
                "unchanged",
                "P37 final approval cannot write or project writes to learning_samples",
            ),
            self._manual_evidence_check(
                "approval_metadata_present",
                "passed" if bool(approved_by) and approval_decision in allowed_decisions else "blocked",
                {"approved_by_present": bool(approved_by), "approval_decision": approval_decision},
                sorted(allowed_decisions),
                "operator final approval metadata must be explicit and constrained",
            ),
            self._manual_evidence_check(
                "approval_decision_allows_final_preflight_only",
                "passed"
                if approval_decision
                == "approved_for_controlled_cleanup_apply_execution_plan_execution_final_preflight"
                else "blocked",
                approval_decision,
                "approved_for_controlled_cleanup_apply_execution_plan_execution_final_preflight",
                "needs_revision or rejected final approvals cannot advance to later preflight",
            ),
            self._manual_evidence_check(
                "source_review_kept_execution_blocked",
                "passed"
                if decision.get("cleanup_execution_approved_now") is False
                and decision.get("cleanup_application_allowed_now") is False
                and decision.get("cleanup_executed_now") is False
                and decision.get("can_execute_cleanup_now") is False
                and decision.get("writes_learning_samples_now") is False
                and decision.get("training_started_now") is False
                else "blocked",
                {
                    "cleanup_execution_approved_now": decision.get("cleanup_execution_approved_now"),
                    "cleanup_application_allowed_now": decision.get("cleanup_application_allowed_now"),
                    "cleanup_executed_now": decision.get("cleanup_executed_now"),
                    "can_execute_cleanup_now": decision.get("can_execute_cleanup_now"),
                    "writes_learning_samples_now": decision.get("writes_learning_samples_now"),
                    "training_started_now": decision.get("training_started_now"),
                },
                "all false",
                "P36 review must not have executed cleanup or training",
            ),
            self._manual_evidence_check(
                "cleanup_and_training_remain_blocked",
                "passed",
                {
                    "cleanup_execution_approved_now": False,
                    "cleanup_application_allowed_now": False,
                    "cleanup_executed_now": False,
                    "can_execute_cleanup_now": False,
                    "writes_learning_samples_now": False,
                    "training_started_now": False,
                },
                "all false",
                "P37 records final approval metadata only; cleanup execution and training stay blocked",
            ),
        ]

