    def _controlled_apply_execution_plan_execution_final_execution_preflight_checks(
        self,
        final_execution_approval: dict[str, Any],
        preflight: dict[str, Any],
        requested_by: str,
        preflight_decision: str,
    ) -> list[dict[str, Any]]:
        summary = final_execution_approval.get("summary") or {}
        decision = final_execution_approval.get("decision") or {}
        approval_scope = final_execution_approval.get("approval_scope") or {}
        blocked_check_count = int(summary.get("blocked_check_count") or 0)
        allowed_decisions = {
            "prepared_for_controlled_cleanup_apply_execution_plan_execution_final_execution_dry_run",
            "needs_revision",
            "rejected",
        }
        return [
            self._manual_evidence_check(
                "apply_execution_plan_execution_final_execution_approval_available",
                "passed" if final_execution_approval.get("id") else "blocked",
                final_execution_approval.get("id"),
                "existing controlled cleanup apply execution plan execution final execution approval",
                "P42 final execution preflight must reference an existing P41 final execution approval event",
            ),
            self._manual_evidence_check(
                "apply_execution_plan_execution_final_execution_approval_accepted",
                "passed"
                if final_execution_approval.get("status")
                == "controlled_cleanup_apply_execution_plan_execution_final_execution_approval_accepted"
                and decision.get(
                    "controlled_cleanup_apply_execution_plan_execution_final_execution_approval_accepted"
                )
                is True
                and decision.get(
                    "controlled_cleanup_apply_execution_plan_execution_final_execution_approval_ready_for_preflight"
                )
                is True
                else "blocked",
                {
                    "status": final_execution_approval.get("status"),
                    "accepted": decision.get(
                        "controlled_cleanup_apply_execution_plan_execution_final_execution_approval_accepted"
                    ),
                    "ready_for_preflight": decision.get(
                        "controlled_cleanup_apply_execution_plan_execution_final_execution_approval_ready_for_preflight"
                    ),
                },
                "accepted and ready_for_preflight",
                "only an accepted P41 final execution approval can enter final execution preflight",
            ),
            self._manual_evidence_check(
                "source_approval_blocked_checks_clear",
                "passed" if blocked_check_count == 0 else "blocked",
                blocked_check_count,
                0,
                "P41 final execution approval checks must have no blocked items",
            ),
            self._manual_evidence_check(
                "lock_key_present",
                "passed" if bool(preflight.get("lock_key")) else "blocked",
                preflight.get("lock_key"),
                "non-empty lock key",
                "P42 final execution preflight must retain the final execution approval lock key",
            ),
            self._manual_evidence_check(
                "staging_count_still_matches_approval",
                "passed" if preflight.get("staging_count_still_matches") is True else "blocked",
                {
                    "current": preflight.get("staging_record_count"),
                    "approved": preflight.get("approval_staging_record_count"),
                },
                "matching nonzero counts",
                "current staging count must still match the P41 final execution approval scope",
            ),
            self._manual_evidence_check(
                "learning_samples_unchanged",
                "passed" if preflight.get("learning_sample_count_still_matches") is True else "blocked",
                {
                    "current": preflight.get("learning_sample_count"),
                    "approved": preflight.get("approval_learning_sample_count"),
                },
                "matching counts",
                "learning_samples count must still match the P41 final execution approval scope",
            ),
            self._manual_evidence_check(
                "aggregate_final_execution_scope_present",
                "passed" if int(preflight.get("simulated_mutation_count") or 0) > 0 else "blocked",
                preflight.get("simulated_mutation_count"),
                ">0",
                "final execution preflight needs aggregate simulated final execution impact",
            ),
            self._manual_evidence_check(
                "manual_backfill_separated",
                "warning" if int(preflight.get("manual_operation_count") or 0) > 0 else "passed",
                {"manual_operation_count": preflight.get("manual_operation_count")},
                "manual operations tracked separately",
                "manual backfill remains a future review item and is not executed by this final execution preflight",
            ),
            self._manual_evidence_check(
                "transaction_and_rollback_required",
                "passed"
                if preflight.get("transaction_required") and preflight.get("rollback_required")
                else "blocked",
                {
                    "transaction_required": preflight.get("transaction_required"),
                    "rollback_required": preflight.get("rollback_required"),
                },
                "transaction and rollback required",
                "future final execution dry-run cannot proceed without transaction and rollback gates",
            ),
            self._manual_evidence_check(
                "table_scope_limited",
                "passed"
                if preflight.get("allowed_tables") == ["dataset2_staging_records"]
                and "learning_samples" in (preflight.get("forbidden_tables") or [])
                else "blocked",
                {
                    "allowed_tables": preflight.get("allowed_tables"),
                    "forbidden_tables": preflight.get("forbidden_tables"),
                },
                "dataset2_staging_records only; learning_samples forbidden",
                "P42 final execution preflight can only scope future work to staging records",
            ),
            self._manual_evidence_check(
                "source_approval_contains_no_executable_payload",
                "passed"
                if not approval_scope.get("contains_sql")
                and not approval_scope.get("contains_executable_code")
                and not approval_scope.get("can_execute_now")
                else "blocked",
                {
                    "contains_sql": bool(approval_scope.get("contains_sql")),
                    "contains_executable_code": bool(approval_scope.get("contains_executable_code")),
                    "can_execute_now": bool(approval_scope.get("can_execute_now")),
                },
                "all false",
                "P41 approval scope cannot contain executable payloads",
            ),
            self._manual_evidence_check(
                "preflight_contains_no_executable_payload",
                "passed"
                if not preflight.get("contains_sql")
                and not preflight.get("contains_executable_code")
                and not preflight.get("can_execute_now")
                else "blocked",
                {
                    "contains_sql": bool(preflight.get("contains_sql")),
                    "contains_executable_code": bool(preflight.get("contains_executable_code")),
                    "can_execute_now": bool(preflight.get("can_execute_now")),
                },
                "all false",
                "P42 final execution preflight cannot include SQL, runnable code, or execution permission",
            ),
            self._manual_evidence_check(
                "aggregate_only_no_record_bodies",
                "passed"
                if preflight.get("record_bodies_included") is False
                and preflight.get("affected_rows_body_included") is False
                else "blocked",
                {
                    "record_bodies_included": preflight.get("record_bodies_included"),
                    "affected_rows_body_included": preflight.get("affected_rows_body_included"),
                },
                "no record bodies",
                "controlled final execution preflight may store aggregate metadata only",
            ),
            self._manual_evidence_check(
                "preflight_metadata_present",
                "passed" if bool(requested_by) and preflight_decision in allowed_decisions else "blocked",
                {"requested_by_present": bool(requested_by), "preflight_decision": preflight_decision},
                sorted(allowed_decisions),
                "operator final execution preflight metadata must be explicit and constrained",
            ),
            self._manual_evidence_check(
                "preflight_decision_allows_final_execution_dry_run_only",
                "passed"
                if preflight_decision
                == "prepared_for_controlled_cleanup_apply_execution_plan_execution_final_execution_dry_run"
                else "blocked",
                preflight_decision,
                "prepared_for_controlled_cleanup_apply_execution_plan_execution_final_execution_dry_run",
                "needs_revision or rejected final execution preflights cannot advance to later dry-run",
            ),
            self._manual_evidence_check(
                "source_approval_kept_execution_blocked",
                "passed"
                if decision.get("cleanup_execution_approved_now") is False
                and decision.get("cleanup_application_allowed_now") is False
                and decision.get("cleanup_executed_now") is False
                and decision.get("can_execute_cleanup_now") is False
                and decision.get("writes_learning_samples_now") is False
                and decision.get("training_started_now") is False
                else "blocked",
                {
                    "cleanup_execution_approved_now": decision.get("cleanup_execution_approved_now"),
                    "cleanup_application_allowed_now": decision.get("cleanup_application_allowed_now"),
                    "cleanup_executed_now": decision.get("cleanup_executed_now"),
                    "can_execute_cleanup_now": decision.get("can_execute_cleanup_now"),
                    "writes_learning_samples_now": decision.get("writes_learning_samples_now"),
                    "training_started_now": decision.get("training_started_now"),
                },
                "all false",
                "P41 approval must not have executed cleanup or training",
            ),
            self._manual_evidence_check(
                "cleanup_and_training_remain_blocked",
                "passed",
                {
                    "cleanup_execution_approved_now": False,
                    "cleanup_application_allowed_now": False,
                    "cleanup_executed_now": False,
                    "can_execute_cleanup_now": False,
                    "writes_learning_samples_now": False,
                    "training_started_now": False,
                },
                "all false",
                "P42 records final execution preflight metadata only; cleanup execution and training stay blocked",
            ),
        ]

